function emitGovernProtocol(program: Program, project: Project, repoRoot: string): void {
  const ns = findNamespace(program, 'OpenboxGovern');
  if (!ns) return;

  const out = project.createSourceFile(
    resolvePath(repoRoot, 'ts/src/core-client/generated/govern.ts'),
    '',
    { overwrite: true },
  );
  out.insertText(0, BANNER + '\n\n');

  // Mark the verdict model so downstream code can branch off it.
  let verdictModelName = 'WorkflowVerdict';
  for (const [modelName, model] of ns.models) {
    if (isVerdict(program, model)) {
      verdictModelName = modelName;
      break;
    }
  }

  // Tier 1; emit every enum + model in the namespace (CanonicalEventType,
  // ActivityStage, VerdictArm, WorkflowVerdict, GovernedPayload). These
  // are the locked envelope plus the public verdict + payload shapes.
  for (const [enumName, enumType] of ns.enums) {
    const members = [...enumType.members.values()].map((m) =>
      JSON.stringify(m.value ?? m.name),
    );
    out.addStatements([`export type ${enumName} = ${members.join(' | ')};`, '']);
  }
  for (const [modelName, model] of ns.models) {
    if (modelName === 'Array' || modelName === 'Record') continue;
    out.addStatements([
      emitInterface(modelName, model, {
        terminalVerdict: modelName === verdictModelName,
      }),
      '',
    ]);
  }

  for (const [modelName, model] of ns.models) {
    if (isVerdict(program, model)) {
      out.addStatements([`export type CanonicalVerdict = ${modelName};`, '']);
      break;
    }
  }

  // Tier 2; walk every @preset interface, collect methods + envelope
  // mappings. The `custom` preset is special: its `activity` operation
  // takes (activityType, stage, payload) and routes via the runtime,
  // so we don't bake a fixed envelope into the method.
  const presets = collectGovernPresetEntries(program, ns);
  if (presets.length === 0) return;

  // Emit the manifest (one JSON-friendly entry per preset method) so
  // tests and downstream tooling can introspect what shipped.
  const manifest = governPresetManifestFromEntries(presets);
  const presetActivityTypes = presetActivityTypesFromManifest(manifest);
  out.addStatements([
    '/** Spec-driven manifest of every preset + its method envelopes. */',
    `export const PRESET_MANIFEST = ${JSON.stringify(manifest, null, 2)} as const;`,
    '',
    'export type PresetName = (typeof PRESET_MANIFEST)[number]["preset"];',
    '',
    '/** Spec-driven fixed activity_type lookup by preset method.',
    ' *  Free-form custom-preset methods are intentionally omitted. */',
    `export const PRESET_ACTIVITY_TYPES = ${JSON.stringify(presetActivityTypes, null, 2)} as const;`,
    '',
    'export type PresetActivityTypes = typeof PRESET_ACTIVITY_TYPES;',
    '',
  ]);

  // Spec-driven canonical sets; used by session inspect, agent audit,
  // verify, and any other tooling that needs to know "which strings
  // are protocol-conformant?" Without these, every consumer hardcodes
  // the same lists and they drift.
  const eventTypeMembers: string[] = [];
  for (const [enumName, enumType] of ns.enums) {
    if (enumName === 'CanonicalEventType') {
      for (const m of enumType.members.values()) {
        eventTypeMembers.push(String(m.value ?? m.name));
      }
    }
  }
  const verdictArmMembers: string[] = [];
  for (const [enumName, enumType] of ns.enums) {
    if (enumName === 'VerdictArm') {
      for (const m of enumType.members.values()) {
        verdictArmMembers.push(String(m.value ?? m.name));
      }
    }
  }
  const activityTypes = new Set<string>();
  for (const p of manifest) {
    for (const m of p.methods) {
      if (m.activityType) activityTypes.add(m.activityType);
    }
  }
  // Also pull activity_types from every @activityRouting table on the
  // adapters. Walk the adapters namespace.
  const adaptersNs = findNamespace(program, 'OpenboxGovern.Adapters');
  if (adaptersNs) {
    for (const [, iface] of adaptersNs.interfaces) {
      for (const [, op] of iface.operations) {
        const ar = getActivityRouting(program, op);
        if (ar) {
          for (const v of Object.values(ar.table)) activityTypes.add(v);
        }
        const at = getActivityType(program, op);
        if (at) activityTypes.add(at);
      }
    }
  }
  // Spec-driven display labels for canonical activity_type strings.
  // The single source of truth for any consumer that renders activity
  // types in a UI; the @activityLabels decorator on the OpenboxGovern
  // namespace declares the table; we emit it as a frozen object so
  // mobile/web/CLI consumers all read the same labels.
  const labelsBinding = getActivityLabels(program, ns);
  const labelTable: Record<string, string> = {};
  if (labelsBinding) {
    // Restrict to canonical activity_types so the emitted table can't
    // drift past the spec-recognized vocabulary. Non-canonical entries
    // in @activityLabels are silently dropped; consumers fall back to
    // the Title-Case formatter for unknown activity_types regardless.
    for (const [k, v] of Object.entries(labelsBinding.table)) {
      if (activityTypes.has(k)) labelTable[k] = v;
    }
  }
  // Stable key order for deterministic output.
  const sortedLabels: Record<string, string> = {};
  for (const k of Object.keys(labelTable).sort()) sortedLabels[k] = labelTable[k];
  const sortedEventTypeMembers = [...eventTypeMembers].sort();
  const eventTypeConstants = Object.fromEntries(
    sortedEventTypeMembers.map((eventType) => [eventConstPrefix(eventType), eventType]),
  );

  out.addStatements([
    '/** Named event_type constants generated from CanonicalEventType.',
    ' *  Runtime/adapters should import this instead of duplicating',
    ' *  ActivityStarted / ActivityCompleted / SignalReceived strings. */',
    `export const CANONICAL_EVENT_TYPE = ${JSON.stringify(
      eventTypeConstants,
      null,
      2,
    )} as const satisfies Record<string, CanonicalEventType>;`,
    '',
    '/** The 7 canonical event_type strings. Anything else on the wire',
    ' *  is a protocol bug. Consumed by the session-inspect protocol',
    ' *  checker + the verify static linter. */',
    `export const CANONICAL_EVENT_TYPES: ReadonlySet<CanonicalEventType> = new Set(${JSON.stringify(
      sortedEventTypeMembers,
    )} as const);`,
    '',
    '/** Every activity_type string declared in any @preset method or',
    ' *  @activityRouting adapter table. Activity_type is free-form on',
    ' *  the wire (custom agents legitimately emit custom names); this',
    ' *  is the *first-party* vocabulary, useful for guardrail authors',
    ' *  and conformance reports. */',
    `export const CANONICAL_ACTIVITY_TYPES: ReadonlySet<string> = new Set(${JSON.stringify(
      [...activityTypes].sort(),
    )});`,
    '',
    '/** Spec-driven display label for each canonical activity_type.',
    ' *  Source of truth for any UI that renders activity types',
    ' *  (mobile, web dashboard, CLI list views, audit reports). Consumers',
    ' *  fall back to a Title-Case formatter for activity_types not in',
    ' *  this table; custom-preset domain agents emit free-form strings',
    ' *  that legitimately aren\'t covered here. */',
    `export const CANONICAL_ACTIVITY_LABELS: Readonly<Record<string, string>> = Object.freeze(${JSON.stringify(
      sortedLabels,
    )});`,
    '',
    '/** Every verdict arm the runtime emits. Production sets typically',
    ' *  exclude `constrain`; consumers can re-filter. */',
    `export const CANONICAL_VERDICT_ARMS: ReadonlySet<VerdictArm> = new Set(${JSON.stringify(
      verdictArmMembers.sort(),
    )} as const);`,
    '',
  ]);

  out.addStatements([emitBaseSession(verdictModelName), '']);
  for (const p of presets) {
    out.addStatements([emitPresetSession(p, verdictModelName), '']);
  }
  out.addStatements([emitPresetsRegistry(presets), '']);
  out.addStatements([emitGovernHelper(verdictModelName), '']);
  out.addStatements([emitVerdictHelpers(verdictModelName), '']);
}

function kebabToCamel(s: string): string {
  return s.replace(/-([a-z])/g, (_, c: string) => c.toUpperCase());
}

// ---------------------------------------------------------------------------
// Adapter emit (Stage 1.4)
//
// Walks the OpenboxGovern.Adapters namespace, finds every interface
// carrying @adapter, and materializes one runtime/<name>.ts module per
// adapter. The module exports a `createXxxAdapter()` factory that:
//   1. Reads stdin JSON.
//   2. Dispatches by the adapter's discriminator field to the matching
//      @hookEvent operation's user-supplied handler.
//   3. Translates the WorkflowVerdict the handler returns to stdout
//      JSON via a fixed @verdictShape registry.
//   4. Writes stdout + exits 0.
//
// User code provides the handler bodies (typically calling a preset
// Session method); the spec-driven adapter handles all transport boilerplate.
// ---------------------------------------------------------------------------

interface AdapterMethod {
  name: string;
  eventName: string;
  shape: VerdictShape;
  /** Optional sub-discriminator → activity_type table from @activityRouting. */
  routing?: Record<string, string>;
  /** Single fixed activity_type from @activityType (mutually exclusive with routing). */
  activityType?: string;
  /** Spec-driven payload shape from @payloadShape. */
  payload?: PayloadShapeBinding;
  /** Marked @noPayload; explicit "this op has no scannable payload". */
  noPayload?: boolean;
  /** Per-event install timeout (claude-array style only). */
  installTimeout?: number;
  /** Whether host/plugin installers include the event by default. */
  installDefault?: boolean;
  /** Predicate-based activity-type reroutes from @activityVariant. */
  variants?: ActivityVariant[];
  /** Human-readable display label from @hookEventLabel. */
  eventLabel?: string;
}

interface AdapterEntry {
  /** Adapter name (`claude-hooks`, `cursor-hooks`). */
  name: string;
  /** Bound preset name (`claude-code`, `cursor`). */
  preset: string;
  /** Stdin JSON discriminator field. */
  discriminator: string;
  /** Generated factory class name (`ClaudeHooks` → `createClaudeHooksAdapter`). */
  pascal: string;
  /** Envelope model name from the operations' parameter type. */
  envelopeName: string;
  methods: AdapterMethod[];
  /** Union of all sideEffect kinds invoked by any method's payload shape. */
  sideEffectKinds: string[];
  /** Spec-driven hook metadata; absent if no @hookTarget. */
  hookTarget?: HookTargetBinding;
}

function emitAdapters(program: Program, project: Project, repoRoot: string): void {
  const ns = findNamespace(program, 'OpenboxGovern.Adapters');
  if (!ns) return;

  const adapters: AdapterEntry[] = [];
  for (const [ifaceName, iface] of ns.interfaces) {
    const binding = getAdapter(program, iface);
    if (!binding) continue;

    let envelopeName: string | undefined;
    const methods: AdapterMethod[] = [];
    for (const [opName, op] of iface.operations) {
      const ev = getHookEvent(program, op);
      if (!ev) continue;
      const vs = getVerdictShape(program, op);
      if (!vs) continue;
      const param = op.parameters?.properties?.values().next().value;
      if (param?.type?.kind === 'Model') {
        envelopeName ??= param.type.name;
      }
      const ar = getActivityRouting(program, op);
      const at = getActivityType(program, op);
      if (ar && at) {
        // Mutually exclusive: either route by tool, or have a fixed
        // type; not both.
        throw new Error(
          `${ifaceName}.${opName}: @activityRouting and @activityType are mutually exclusive`,
        );
      }
      const ps = getPayloadShape(program, op);
      const np = isNoPayload(program, op);
      const it = getInstallTimeout(program, op);
      const id = getInstallDefault(program, op);
      const av = getActivityVariants(program, op);
      const hl = getHookEventLabel(program, op);
      methods.push({
        name: opName,
        eventName: ev.eventName,
        shape: vs.shape,
        routing: ar?.table,
        activityType: at,
        payload: ps,
        noPayload: np,
        installTimeout: it,
        installDefault: id,
        variants: av,
        eventLabel: hl,
      });
    }
    if (methods.length === 0) continue;
    const sideEffectKinds = new Set<string>();
    for (const m of methods) {
      if (m.payload) {
        for (const k of m.payload.sideEffectKinds) sideEffectKinds.add(k);
      }
    }
    adapters.push({
      name: binding.name,
      preset: binding.preset,
      discriminator: binding.discriminator,
      pascal: pascal(binding.name.replace(/-/g, '_')),
      envelopeName: envelopeName ?? 'unknown',
      methods,
      sideEffectKinds: [...sideEffectKinds].sort(),
      hookTarget: getHookTarget(program, iface),
    });
  }
  if (adapters.length === 0) return;

  // Stable order; file ordering needs to be deterministic.
  adapters.sort((a, b) => a.name.localeCompare(b.name));

  // Emit envelope models from the Adapters namespace into a shared types
  // file, plus one runtime/<name>.ts per adapter that imports them.
  const sharedTypes = project.createSourceFile(
    resolvePath(repoRoot, 'ts/src/core-client/generated/runtime/envelopes.ts'),
    '',
    { overwrite: true },
  );
  sharedTypes.insertText(0, BANNER + '\n\n');
  for (const [modelName, model] of ns.models) {
    if (modelName === 'Array' || modelName === 'Record') continue;
    sharedTypes.addStatements([emitInterface(modelName, model), '']);
  }
  sharedTypes.replaceWithText(sharedTypes.getFullText().replace(/\n{3,}$/g, '\n'));

  for (const a of adapters) {
    const out = project.createSourceFile(
      resolvePath(repoRoot, `ts/src/core-client/generated/runtime/${a.name}.ts`),
      '',
      { overwrite: true },
    );
    out.insertText(0, BANNER + '\n\n');
    out.addStatements([emitAdapterModule(a), '']);
  }

  // Index re-export so consumers can import via `runtime/<name>`.
  const index = project.createSourceFile(
    resolvePath(repoRoot, 'ts/src/core-client/generated/runtime/index.ts'),
    '',
    { overwrite: true },
  );
  // Adapter modules share several symbol names by design (each preset has its
  // own HOOK_SPEC, PRE_TOOL_USE_ROUTING, build*Payload, etc). A flat
  // `export *` from each would collide, so namespace each adapter under its
  // kebab-cased name. Consumers should import directly from the per-adapter
  // module (`./claude-code.js`, `./cursor.js`); the namespaces here are a
  // convenience for tooling that walks the barrel.
  index.insertText(0, BANNER + '\n\n');
  index.addStatements([
    `export * from './envelopes.js';`,
    ...adapters.map(
      (a) => `export * as ${kebabToCamel(a.name)} from './${a.name}.js';`,
    ),
    '',
  ]);
}

function emitAdapterModule(a: AdapterEntry): string {
  const factoryName = `create${a.pascal}Adapter`;
  const handlersIface = `${a.pascal}AdapterHandlers`;
  const configIface = `${a.pascal}AdapterConfig`;
  const presetCamel = kebabToCamel(a.preset);
  const presetSessionTy = `${pascal(a.preset.replace(/-/g, '_'))}Session`;

  const handlerSigs = a.methods
    .map(
      (m) =>
        `  ${m.name}?: (input: ${a.envelopeName}, session: ${presetSessionTy}) => Promise<WorkflowVerdict | undefined | void>;`,
    )
    .join('\n');

  const dispatchCases = a.methods
    .map(
      (m) =>
        `    case ${JSON.stringify(m.eventName)}: {
      if (!handlers.${m.name}) {
        writeFallback(${JSON.stringify(m.shape)}, undefined, env);
        return;
      }
      const verdict = await handlers.${m.name}(env, session);
      writeVerdict(${JSON.stringify(m.shape)}, verdict, env);
      return;
    }`,
    )
    .join('\n');

  // Routing constants per @activityRouting on each operation. The constant
  // name is `<EVENT_NAME>_ROUTING` in SCREAMING_SNAKE_CASE so consumer
  // mappers can reach for it without per-platform aliasing.
  const routingExports = a.methods
    .filter((m) => m.routing && Object.keys(m.routing).length > 0)
    .map((m) => {
      const constName = eventConstPrefix(m.eventName) + '_ROUTING';
      return `export const ${constName}: Record<string, string> = ${JSON.stringify(m.routing, null, 2)};`;
    })
    .join('\n\n');

  // Activity-type constants per @activityType on each operation. One
  // canonical activity_type per event; mappers import the constant
  // instead of hand-coding strings.
  const activityTypeExports = a.methods
    .filter((m) => m.activityType)
    .map((m) => {
      const constName = eventConstPrefix(m.eventName) + '_ACTIVITY_TYPE';
      return `export const ${constName}: string = ${JSON.stringify(m.activityType)};`;
    })
    .join('\n\n');

  // Predicate-based reroute tables per @activityVariant. One table per
  // op; the runtime helper applyActivityVariant() picks the first match.
  const variantExports = a.methods
    .filter((m) => m.variants && m.variants.length > 0)
    .map((m) => {
      const constName = eventConstPrefix(m.eventName) + '_VARIANTS';
      return `export const ${constName}: ActivityVariant[] = ${JSON.stringify(m.variants, null, 2)};`;
    })
    .join('\n\n');
  const hasAnyVariants = a.methods.some((m) => m.variants && m.variants.length > 0);

  // Per-event payload builders emitted from @payloadShape. Each
  // adapter mapper imports the builder for its event instead of
  // hand-coding per-tool field extraction.
  const sideEffectsIface = `${a.pascal}SideEffects`;
  const payloadBuilders = a.methods
    .filter((m) => m.payload)
    .map((m) => emitPayloadBuilder(a, m))
    .join('\n\n');
  const sideEffectsBlock = emitSideEffectsInterface(sideEffectsIface, a.sideEffectKinds);

  // Hook metadata used by runtime installers and plugin exporters.
  const hookSpec = a.hookTarget ? emitHookSpec(a) : '';

  // Per-event human display labels. UI surfaces (toast titles,
  // detail panels, mobile sheets) read this map so labels stay
  // consistent across consumers.
  const labelEntries: Array<[string, string]> = [];
  for (const m of a.methods) {
    if (m.eventLabel) labelEntries.push([m.eventName, m.eventLabel]);
  }
  const hookLabelsExport =
    labelEntries.length === 0
      ? ''
      : `export const HOOK_EVENT_LABELS: Record<string, string> = ${JSON.stringify(
          Object.fromEntries(labelEntries),
          null,
          2,
        )};`;

  return `import type { OpenBoxCoreClient } from '../../core-client.js';
import { govern, presets, type ${presetSessionTy}, type WorkflowVerdict } from '../govern.js';
import type { ${a.envelopeName} } from './envelopes.js';

export type { ${a.envelopeName} };

${routingExports ? routingExports + '\n\n' : ''}${activityTypeExports ? activityTypeExports + '\n\n' : ''}${hookLabelsExport ? hookLabelsExport + '\n\n' : ''}${hookSpec ? hookSpec + '\n\n' : ''}${hasAnyVariants ? VARIANT_RUNTIME_HELPERS + '\n\n' + variantExports + '\n\n' : ''}${sideEffectsBlock ? sideEffectsBlock + '\n\n' : ''}${payloadBuilders ? PAYLOAD_RUNTIME_HELPERS + '\n\n' + payloadBuilders + '\n\n' : ''}/**
 * Per-event handlers. Each handler receives the parsed stdin envelope
 * + an attached ${presetSessionTy} (workflowId/runId resolved by
 * \`config.resolveSession\`). Return a WorkflowVerdict; usually by calling
 * a preset method like \`session.preToolUse(...)\`. The adapter writes
 * the verdict-mapped stdout JSON automatically per the operation's
 * @verdictShape. Returning undefined writes the default \`allow\` shape.
 */
export interface ${handlersIface} {
${handlerSigs}
}

export interface ${configIface} {
  /** Authenticated core client (agent-scoped API key). */
  core: OpenBoxCoreClient;
  /** Per-stdin-message resolver; typically reads sessionStore.json. */
  resolveSession: (
    env: ${a.envelopeName},
  ) => Promise<{ workflowId: string; runId: string }>;
  handlers: ${handlersIface};
  /** Override stdin source (test injection). Default: process.stdin. */
  readStdin?: () => Promise<string>;
  /** Override stdout sink (test injection). Default: process.stdout.write. */
  writeStdout?: (data: string) => void;
  /** Override exit (test injection). Default: process.exit. */
  exit?: (code: number) => never;
  /**
   * @deprecated Compatibility no-op. Approval expiration is controlled
   * by the server-owned approval row state.
   */
  approvalMaxWaitMs?: number;
  /**
   * When true, the SDK skips the in-process poll loop on a
   * require_approval verdict and renders \`permissionDecision: 'ask'\`
   * (or the host equivalent), which makes the host's native
   * permission dialog pop inline. The local user becomes the
   * approver. External approval clients such as the dashboard, mobile
   * app, or editor extension can still resolve the backend row, but
   * the hook subprocess does not wait for them. Adapters wire this
   * from the project \`approvalMode\` config.
   */
  inlineApproval?: boolean;
  deferApproval?: boolean;
  /**
   * Fired the moment the backend returns require_approval; before
   * the SDK starts polling. Receives the approval metadata plus the
   * stdin envelope (so harness code can correlate on conversation_id /
   * hook_event_name / prompt). Used by the hook handler to write a
   * pending-approval marker for the OpenBox extension.
   */
  onPendingApproval?: (
    info: { approvalId: string; governanceEventId?: string; activityId: string; activityType: string; expiresAt?: string; reason?: string },
    env: ${a.envelopeName},
  ) => void | Promise<void>;
  /**
   * Fired when pollApproval resolves OR times out. Lets the harness
   * clear pending markers and any inline UI it staged.
   */
  onApprovalResolved?: (
    info: { approvalId: string; activityId: string; activityType: string; arm: string },
    env: ${a.envelopeName},
  ) => void | Promise<void>;
  /**
   * Optional out-of-band decision channel. When the harness has a
   * faster path than HTTP polling (e.g. a local IPC socket from a UI
   * extension that received an Approve / Deny click) it can return a
   * promise that resolves when that decision is in. The poll loop
   * races this promise against its normal HTTP cycle and runs a
   * confirmatory pollApproval as soon as either fires.
   */
  awaitExternalDecision?: (
    info: { approvalId: string; governanceEventId?: string; activityId: string; activityType: string; expiresAt?: string },
    env: ${a.envelopeName},
  ) => Promise<'approve' | 'reject' | undefined>;
}

/**
 * Build the ${a.name} runtime adapter. Call \`.run()\` from the hook
 * binary's main(). Generated from specs/typespec/govern/adapters.tsp.
 */
export function ${factoryName}(config: ${configIface}) {
  const readStdin = config.readStdin ?? defaultReadStdin;
  const write = config.writeStdout ?? ((data: string) => process.stdout.write(data));
  const exit = config.exit ?? ((code: number) => process.exit(code));

  function writeFallback(shape: string, _v: WorkflowVerdict | undefined | void, env: ${a.envelopeName}): void {
    const json = renderVerdictOutput(shape as Shape, undefined, env, config.deferApproval === true);
    if (json !== undefined) write(JSON.stringify(json));
  }
  function writeVerdict(shape: string, v: WorkflowVerdict | undefined | void, env: ${a.envelopeName}): void {
    const json = renderVerdictOutput(shape as Shape, v ?? undefined, env, config.deferApproval === true);
    if (json !== undefined) write(JSON.stringify(json));
  }

  return {
    async run(): Promise<void> {
      const raw = (await readStdin()).trim();
      if (!raw) return exit(0);
      let env: ${a.envelopeName};
      try {
        env = JSON.parse(raw) as ${a.envelopeName};
      } catch {
        return exit(0);
      }
      const eventName = (env as unknown as Record<string, unknown>)[${JSON.stringify(a.discriminator)}];
      if (typeof eventName !== 'string' || !eventName) return exit(0);

      const { workflowId, runId } = await config.resolveSession(env);
      const session = govern.attach({
        core: config.core,
        preset: presets.${presetCamel},
        workflowId,
        runId,
        approvalPollIntervalMs: 500,
        approvalMaxWaitMs: config.approvalMaxWaitMs,
        inlineApproval: config.inlineApproval,
        onPendingApproval: config.onPendingApproval
          ? (info) => config.onPendingApproval!(info, env)
          : undefined,
        onApprovalResolved: config.onApprovalResolved
          ? (info) => config.onApprovalResolved!(info, env)
          : undefined,
        awaitExternalDecision: config.awaitExternalDecision
          ? (info) => config.awaitExternalDecision!(info, env)
          : undefined,
      });

      const handlers = config.handlers;
      try {
        await dispatch(eventName, env, session, handlers, writeFallback, writeVerdict);
      } finally {
        return exit(0);
      }
    },
  };
}

async function dispatch(
  eventName: string,
  env: ${a.envelopeName},
  session: ${presetSessionTy},
  handlers: ${handlersIface},
  writeFallback: (shape: string, v: WorkflowVerdict | undefined | void, env: ${a.envelopeName}) => void,
  writeVerdict: (shape: string, v: WorkflowVerdict | undefined | void, env: ${a.envelopeName}) => void,
): Promise<void> {
  switch (eventName) {
${dispatchCases}
    default:
      return;
  }
}

async function defaultReadStdin(): Promise<string> {
  // 10 MB cap. Hook events from claude-code/cursor are bounded to
  // tens of KB in practice; anything larger is either a runaway log
  // dump or an attacker piping to OOM the hook process. We bail
  // explicitly with a clear error rather than letting the buffer
  // grow without bound.
  const MAX_BYTES = 10 * 1024 * 1024;
  const chunks: Buffer[] = [];
  let total = 0;
  for await (const chunk of process.stdin) {
    const buf = chunk as Buffer;
    total += buf.length;
    if (total > MAX_BYTES) {
      throw new Error(
        \`hook stdin exceeded \${MAX_BYTES.toLocaleString()} bytes; refusing to buffer further (likely runaway pipe or hostile input)\`,
      );
    }
    chunks.push(buf);
  }
  return Buffer.concat(chunks).toString('utf-8');
}

${VERDICT_SHAPE_REGISTRY_SOURCE}
`;
}

/** "PreToolUse" → "PRE_TOOL_USE", "preToolUse" → "PRE_TOOL_USE". Used for routing/payload export const names. */
function eventConstPrefix(eventName: string): string {
  return eventName.replace(/([a-z0-9])([A-Z])/g, '$1_$2').toUpperCase();
}

/** "PreToolUse" → "buildPreToolUsePayload". */
function payloadBuilderName(eventName: string): string {
  const pascal = eventName[0].toUpperCase() + eventName.slice(1);
  return `build${pascal}Payload`;
}

/** Single runtime helper shared by every payload builder in this adapter file. */
const PAYLOAD_RUNTIME_HELPERS = `function getPath(env: unknown, path: string): unknown {
  if (env == null || typeof env !== 'object') return undefined;
  let cur: unknown = env;
  for (const seg of path.split('.')) {
    if (cur == null || typeof cur !== 'object') return undefined;
    cur = (cur as Record<string, unknown>)[seg];
  }
  return cur;
}`;

/** Runtime support for @activityVariant rerouting. The mapper supplies
 *  the base activity_type from @activityRouting and any payload it
 *  built; if any variant matches, the helper returns the override. */
const VARIANT_RUNTIME_HELPERS = `export interface ActivityVariant {
  tool: string;
  field: string;
  pattern: string;
  activityType: string;
  eventCategory?: string;
}

/** Walk the variant table for one tool; return an override on first
 *  match, undefined otherwise. The mapper composes:
 *      const override = applyActivityVariant(VARIANTS, toolName, env);
 *      const activityType = override?.activityType ?? base;
 *      if (override?.eventCategory) payload.event_category = override.eventCategory;
 */
export function applyActivityVariant(
  table: ActivityVariant[],
  toolName: string,
  env: unknown,
): ActivityVariant | undefined {
  for (const v of table) {
    if (v.tool !== toolName) continue;
    const value = String((function getPath(e: unknown, p: string): unknown {
      if (e == null || typeof e !== 'object') return undefined;
      let cur: unknown = e;
      for (const seg of p.split('.')) {
        if (cur == null || typeof cur !== 'object') return undefined;
        cur = (cur as Record<string, unknown>)[seg];
      }
      return cur;
    })(env, v.field) ?? '');
    if (new RegExp(v.pattern).test(value)) return v;
  }
  return undefined;
}`;

function emitSideEffectsInterface(name: string, kinds: string[]): string {
  if (kinds.length === 0) return '';
  const sigs = kinds
    .map((k) => `  /** Supplied by the runtime layer; receives the resolved \`from\` path value. */\n  ${k}?: (input: unknown) => unknown;`)
    .join('\n');
  return `export interface ${name} {\n${sigs}\n}`;
}

/** Compile a single FieldSource to a TS expression that produces its value. */
function compileFieldSource(src: FieldSource): string {
  switch (src.kind) {
    case 'literal':
      return JSON.stringify(src.value);
    case 'from': {
      const paths = [src.path, ...src.fallbacks];
      const lookups = paths.map((p) => `getPath(env, ${JSON.stringify(p)})`);
      const chain = lookups.join(' ?? ');
      const tail = src.defaultLiteral !== undefined ? ` ?? ${JSON.stringify(src.defaultLiteral)}` : '';
      return paths.length === 1 && !src.defaultLiteral ? lookups[0] : `(${chain}${tail})`;
    }
    case 'sideEffect': {
      // Side-effect callbacks may be undefined; supply a benign default ('').
      const arg = `getPath(env, ${JSON.stringify(src.path)})`;
      return `(sideEffects.${src.effect}?.(${arg}) ?? '')`;
    }
  }
}

/** Compile a Record<field, FieldSource> to a TS object-literal expression. */
function compileFieldMap(fields: Record<string, FieldSource>): string {
  const entries = Object.entries(fields)
    .map(([k, v]) => `      ${JSON.stringify(k)}: ${compileFieldSource(v)},`)
    .join('\n');
  return `{\n${entries}\n    }`;
}

/** Emit the per-adapter hook metadata. Runtime installers and plugin
 *  exporters consume it to render host-specific hook configuration. */
function emitHookSpec(a: AdapterEntry): string {
  const it = a.hookTarget!;
  const events = a.methods.map((m) => ({
    name: m.eventName,
    timeout: m.installTimeout,
    installDefault: m.installDefault,
  }));
  const spec = {
    file: it.file,
    key: it.key,
    style: it.style,
    command: it.command,
    configDir: it.configDir,
    events,
  };
  return `export interface HookSpec {
  file: string;
  key: string;
  style: 'claude-array' | 'codex-array' | 'cursor-keyed';
  command: string;
  configDir: string;
  events: Array<{ name: string; timeout?: number; installDefault?: boolean }>;
}

/** Hook metadata for this adapter. Host-specific installers and
 *  plugin exporters consume it to render hook configuration. */
export const HOOK_SPEC: HookSpec = ${JSON.stringify(spec, null, 2)};`;
}

function emitPayloadBuilder(a: AdapterEntry, m: AdapterMethod): string {
  const fnName = payloadBuilderName(m.eventName);
  const sideEffectsTy = `${a.pascal}SideEffects`;
  const ps = m.payload!;
  const hasByTool = Object.keys(ps.byTool).length > 0;
  const hasDefault = Object.keys(ps.defaultFields).length > 0;
  const sideEffectsParam = ps.sideEffectKinds.size > 0
    ? `, sideEffects: ${sideEffectsTy} = {}`
    : '';
  const sideEffectsPrelude =
    ps.sideEffectKinds.size > 0 ? '' : '  /* no side effects */\n';

  const defaultBody = hasDefault ? compileFieldMap(ps.defaultFields) : `{}`;

  if (!hasByTool) {
    return `export function ${fnName}(env: ${a.envelopeName}${sideEffectsParam}): Record<string, unknown> {
${sideEffectsPrelude}
  return ${defaultBody};
}`;
  }

  const cases = Object.entries(ps.byTool)
    .map(([tool, fields]) => `    case ${JSON.stringify(tool)}:\n      return ${compileFieldMap(fields)};`)
    .join('\n');

  return `export function ${fnName}(env: ${a.envelopeName}, toolName: string${sideEffectsParam}): Record<string, unknown> {
${sideEffectsPrelude}
  switch (toolName) {
${cases}
    default:
      return ${defaultBody};
  }
}`;
}

const VERDICT_SHAPE_REGISTRY_SOURCE = `// ─── Verdict-shape registry ─────────────────────────────────────────────
// Translates a WorkflowVerdict to stdout JSON per the operation's
// @verdictShape. Adding a new shape requires extending the union below
// AND updating the typespec-workflow VerdictShape union.

type Shape =
  | 'permission-decision'
  | 'decision-block'
  | 'permission-request'
  | 'permission-denied-retry'
  | 'elicitation-response'
  | 'continue-block'
  | 'additional-context'
  | 'worktree-path'
  | 'cursor-permission'
  | 'cursor-observe'
  | 'cursor-continue'
  | 'none';

/**
 * Normalize and brand any user-facing verdict reason so the host UI
 * (Cursor inline panel, Claude Code stdout) consistently:
 *   - shows it came from OpenBox (rules from the backend usually omit
 *     attribution, so a bare "Behavioral violation: ..." is ambiguous);
 *   - never contains em/en dashes; they are forbidden in user-visible
 *     OpenBox copy. Replaced with ASCII " - ".
 *
 * Idempotent: skips the prefix when the reason already starts with the
 * \`[OpenBox]\` tag.
 */
function brand(raw: string): string {
  // Em dash + en dash become a spaced ASCII hyphen so the result reads as
  // a clause separator. We do NOT touch hyphens that were already in the
  // string (e.g. "high-trust") since those are intra-word.
  const sanitized = raw.replace(/[\\u2014\\u2013]/g, ' - ').replace(/ {2,}/g, ' ').trim();
  if (!sanitized) return '';
  return sanitized.startsWith('[OpenBox]') ? sanitized : '[OpenBox] ' + sanitized;
}

function redactedInput(v: WorkflowVerdict | undefined): unknown {
  return v?.guardrailsResult?.redactedInput;
}

function redactedOutputValue(
  v: WorkflowVerdict | undefined,
  env: Record<string, unknown>,
): unknown {
  const guardrails = v?.guardrailsResult;
  const redactedOutput = guardrails?.redactedOutput ?? guardrails?.redactedInput;
  if (
    !guardrails ||
    guardrails.inputType !== 'activity_output' ||
    redactedOutput === undefined ||
    redactedOutput === null
  ) {
    return undefined;
  }
  return unwrapOutputRedaction(redactedOutput, originalOutputFor(env));
}

function redactedInputRecord(v: WorkflowVerdict | undefined): Record<string, unknown> | undefined {
  return objectRecord(unwrapInputRedaction(redactedInput(v)));
}

function unwrapInputRedaction(value: unknown): unknown {
  if (Array.isArray(value) && value.length === 1) return value[0];
  const record = objectRecord(value);
  if (!record) return value;
  if (Array.isArray(record.input) && record.input.length === 1) return record.input[0];
  if (Array.isArray(record.activity_input) && record.activity_input.length === 1) return record.activity_input[0];
  if (Array.isArray(record.activityInput) && record.activityInput.length === 1) return record.activityInput[0];
  return value;
}

function unwrapOutputRedaction(value: unknown, originalOutput: unknown): unknown {
  const record = objectRecord(value);
  if (!record || hasOwnKey(originalOutput, 'output')) return value;
  if (Object.prototype.hasOwnProperty.call(record, 'output')) return record.output;
  if (Object.prototype.hasOwnProperty.call(record, 'activity_output')) return record.activity_output;
  if (Object.prototype.hasOwnProperty.call(record, 'activityOutput')) return record.activityOutput;
  return value;
}

function originalOutputFor(env: Record<string, unknown>): unknown {
  return env.tool_response ?? env.toolResponse ?? env.response ?? env.content;
}

function hasInputRedaction(v: WorkflowVerdict | undefined): boolean {
  const guardrails = v?.guardrailsResult;
  const hasRedactedField = guardrails?.fieldResults?.some((field) =>
    field.status === 'redacted' || field.status === 'transformed'
  );
  return Boolean(
    guardrails &&
      (guardrails.inputType === 'activity_input' || guardrails.inputType === 'signal_args') &&
      (hasRedactedField ||
        guardrails.redactedInput !== undefined &&
        guardrails.redactedInput !== null),
  );
}

function isSubmittedPromptEvent(eventName: unknown): boolean {
  return eventName === 'UserPromptSubmit' || eventName === 'UserPromptExpansion';
}

function promptRedactionBlockReason(reason: string): string {
  return (
    reason ||
    '[OpenBox] redacted this prompt, but this host cannot replace submitted prompts. Rewrite the prompt with the redacted content and submit again.'
  );
}

function cursorInputRedactionBlockReason(reason: string): string {
  const detail = reason.replace(/[.]+$/, '');
  return detail
    ? detail + '. Cursor cannot replace this hook input, so OpenBox blocked the original action.'
    : '[OpenBox] redacted this action input, but Cursor cannot replace this hook input. Rewrite the action with redacted content and retry.';
}

function missingInputReplacementBlockReason(reason: string): string {
  const detail = reason.replace(/[.]+$/, '');
  return detail
    ? detail + '. OpenBox did not provide replacement input, so the original action was blocked.'
    : '[OpenBox] redacted this action input but did not provide replacement input, so OpenBox blocked the original action.';
}

function objectRecord(value: unknown): Record<string, unknown> | undefined {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return undefined;
  return value as Record<string, unknown>;
}

function hasOwnKey(value: unknown, key: string): value is Record<string, unknown> {
  return Boolean(
    value &&
    typeof value === 'object' &&
    !Array.isArray(value) &&
    Object.prototype.hasOwnProperty.call(value, key)
  );
}

function addIfDefined(target: Record<string, unknown>, key: string, value: unknown): void {
  if (value !== undefined) target[key] = value;
}

function renderVerdictOutput(
  shape: Shape,
  v: WorkflowVerdict | undefined,
  env: { hook_event_name?: string; content?: unknown; response?: unknown },
  deferApproval = false,
): unknown {
  const arm = v?.arm ?? 'allow';
  const reason = brand(v?.reason ?? '');
  switch (shape) {
    case 'permission-decision': {
      const eventName = env.hook_event_name ?? 'PreToolUse';
      if (arm === 'allow' || arm === 'constrain') {
        const hookSpecificOutput: Record<string, unknown> = {
          hookEventName: eventName,
          permissionDecision: 'allow',
        };
        if (arm === 'constrain') {
          const updatedInput = redactedInputRecord(v);
          if (hasInputRedaction(v) && updatedInput === undefined) {
            return {
              hookSpecificOutput: {
                hookEventName: eventName,
                permissionDecision: 'deny',
                permissionDecisionReason: missingInputReplacementBlockReason(reason),
              },
            };
          }
          addIfDefined(hookSpecificOutput, 'updatedInput', updatedInput);
          if (reason) hookSpecificOutput.additionalContext = reason;
        }
        return {
          hookSpecificOutput,
        };
      }
      if (arm === 'require_approval') {
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            permissionDecision: deferApproval ? 'defer' : 'ask',
            permissionDecisionReason: reason || '[OpenBox] approval required',
          },
        };
      }
      // block / halt
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
          permissionDecision: 'deny',
          permissionDecisionReason: reason || '[OpenBox] blocked by policy',
        },
      };
    }
    case 'decision-block': {
      if (arm === 'block' || arm === 'halt') {
        return {
          decision: 'block',
          reason: reason || '[OpenBox] blocked by policy',
        };
      }
      if (arm === 'require_approval') {
        const approvalReason = reason.replace(/^\\[OpenBox\\] /, '').trim();
        return {
          decision: 'block',
          reason:
            '[OpenBox] approval pending' +
            (approvalReason ? ': ' + approvalReason : '') +
            '. Approve in OpenBox, then ask the agent to retry.',
        };
      }
      if (arm === 'constrain' && isSubmittedPromptEvent(env.hook_event_name) && hasInputRedaction(v)) {
        return {
          decision: 'block',
          reason: promptRedactionBlockReason(reason),
          suppressOriginalPrompt: true,
        };
      }
      if (arm === 'constrain') {
        const updatedToolOutput = redactedOutputValue(v, env);
        if (!reason && updatedToolOutput === undefined) return {};
        const hookSpecificOutput: Record<string, unknown> = {
          hookEventName: env.hook_event_name ?? 'ClaudeCode',
        };
        if (reason) hookSpecificOutput.additionalContext = reason;
        addIfDefined(hookSpecificOutput, 'updatedToolOutput', updatedToolOutput);
        return { hookSpecificOutput };
      }
      return {};
    }
    case 'permission-request': {
      const eventName = env.hook_event_name ?? 'PermissionRequest';
      if (arm === 'allow' || arm === 'constrain') {
        const decision: Record<string, unknown> = { behavior: 'allow' };
        if (arm === 'constrain') {
          const updatedInput = redactedInputRecord(v);
          if (hasInputRedaction(v) && updatedInput === undefined) {
            return {
              hookSpecificOutput: {
                hookEventName: eventName,
                decision: {
                  behavior: 'deny',
                  message: missingInputReplacementBlockReason(reason),
                },
              },
            };
          }
          addIfDefined(decision, 'updatedInput', updatedInput);
        }
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            decision,
          },
        };
      }
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
          decision: {
            behavior: 'deny',
            message: reason || '[OpenBox] blocked by policy',
          },
        },
      };
    }
    case 'permission-denied-retry': {
      const eventName = env.hook_event_name ?? 'PermissionDenied';
      if (arm === 'allow' || arm === 'constrain') {
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            retry: true,
          },
        };
      }
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
          retry: false,
        },
      };
    }
    case 'elicitation-response': {
      const eventName = env.hook_event_name ?? 'Elicitation';
      if (arm === 'allow') return {};
      if (arm === 'constrain') {
        const content = redactedInputRecord(v);
        if (hasInputRedaction(v) && content === undefined) {
          return {
            hookSpecificOutput: {
              hookEventName: eventName,
              action: 'decline',
              content: {},
            },
          };
        }
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            action: 'accept',
            content: content ?? objectRecord(env.response) ?? objectRecord(env.content) ?? {},
          },
        };
      }
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
          action: arm === 'halt' ? 'cancel' : 'decline',
          content: {},
        },
      };
    }
    case 'continue-block': {
      if (arm === 'allow' || arm === 'constrain') return {};
      return {
        continue: false,
        stopReason: reason || '[OpenBox] blocked by policy',
      };
    }
    case 'additional-context': {
      if (arm === 'allow') return {};
      return {
        hookSpecificOutput: {
          hookEventName: env.hook_event_name ?? 'PostToolUseFailure',
          additionalContext: reason || '[OpenBox] blocked by policy',
        },
      };
    }
    case 'worktree-path': {
      const eventName = env.hook_event_name ?? 'WorktreeCreate';
      const worktreePath = typeof (env as Record<string, unknown>).worktree_path === 'string'
        ? ((env as Record<string, unknown>).worktree_path as string).trim()
        : '';
      if ((arm === 'allow' || arm === 'constrain') && worktreePath) {
        return {
          hookSpecificOutput: {
            hookEventName: eventName,
            worktreePath,
          },
        };
      }
      return {
        hookSpecificOutput: {
          hookEventName: eventName,
        },
        systemMessage: reason || '[OpenBox] worktree creation blocked.',
      };
    }
    case 'cursor-permission': {
      // Per cursor.com/docs/hooks: user_message / agent_message are
      // snake_case. Permission consumer surface (confirmed via the
      // Cursor bundle):
      //   - \`permission==="deny"\` is honored on 3 events: subagentStart,
      //     beforeReadFile, beforeTabFileRead. The other validators
      //     accept the field but no code path branches on it, so the
      //     tool proceeds. Returning \`deny\` is the only universally
      //     working gate for the events the SDK targets.
      //   - \`permission==="ask"\` has exactly one consumer:
      //     subagentStart, which throws "not yet implemented".
      //     For shell / MCP / preToolUse, returning \`ask\` is silently
      //     equivalent to "proceed" (validator accepts, no consumer
      //     reads the value, the tool runs). For beforeReadFile /
      //     beforeTabFileRead, the validator rejects \`ask\` outright.
      // We always return \`deny\` for require_approval and surface our
      // own toast / panel as the actual gate.
      if (arm === 'allow') return { permission: 'allow' };
      if (arm === 'constrain') {
        if (hasInputRedaction(v)) {
          const message = cursorInputRedactionBlockReason(reason);
          return {
            permission: 'deny',
            user_message: message,
            agent_message: message,
          };
        }
        return { permission: 'allow' };
      }
      if (arm === 'require_approval') {
        const r = reason.replace(/^\\[OpenBox\\] /, '').trim();
        // Reaching this branch means Core still reports require_approval.
        // The host blocks this tool attempt; the user can approve and retry.
        return {
          permission: 'deny',
          user_message:
            '[OpenBox] approval pending' +
            (r ? ': ' + r : '') +
            '. Click Approve in the OpenBox notification, then ask the agent to retry.',
          // Direct LLM instruction. (a) Force the brand into the
          // chat text the LLM will write so the user sees who
          // gated the action; Cursor's chat doesn't insert that
          // for us on most events (only subagentStart has the
          // hardcoded "Subagent creation blocked by hook:" prefix).
          // (b) Hard-stop the LLM's tendency to promise auto-retry,
          // which it can't deliver because Cursor's hook protocol
          // is one-shot.
          agent_message:
            "[OpenBox] blocked this action. Tell the user verbatim: " +
            "'OpenBox is gating this action. Approve it in the OpenBox notification, " +
            "then ask me to retry.' Then STOP. " +
            "Do NOT retry on your own. " +
            "Do NOT speculate, describe, or invent what the blocked command WOULD have produced; " +
            "you didn't run it, you don't know. " +
            "Do NOT show 'expected output' or 'if you run it locally'. " +
            "Just relay the gate message and wait for approval.",
        };
      }
      if (arm === 'halt') {
        return {
          permission: 'deny',
          user_message: '[OpenBox] HALT: ' + (reason.replace(/^\\[OpenBox\\] /, '') || 'session halted'),
          agent_message: '[OpenBox] HALT: do not proceed',
        };
      }
      return {
        permission: 'deny',
        user_message: reason || '[OpenBox] blocked by policy',
      };
    }
    case 'cursor-continue': {
      // Cursor's beforeSubmitPrompt verdict shape.
       // Stdout is { continue: bool, user_message?: string };       // distinct from cursor-permission (which uses 'permission').
      // Per cursor.com/docs/hooks.
      if (arm === 'constrain' && hasInputRedaction(v)) {
        return {
          continue: false,
          user_message: promptRedactionBlockReason(reason),
        };
      }
      if (arm === 'allow' || arm === 'constrain') return { continue: true };
      if (arm === 'require_approval') {
        // Cursor's beforeSubmitPrompt API is fire-and-forget: stdout
        // is { continue: bool }, no inline-ask surface, no resume
        // hook. If pollApproval times out without a decision, the only
        // signal we can give is "we dropped this one; approve and
        // retype." Cursor cannot resume a submitted prompt after the
        // hook returns continue:false.
        const r = reason.replace(/^\\[OpenBox\\] /, '').trim();
        return {
          continue: false,
          user_message:
            '[OpenBox] approval needed' +
            (r ? ': ' + r : '') +
            '. Approve in the OpenBox notification, then resubmit your prompt (Cursor cannot resume a submitted prompt).',
        };
      }
      if (arm === 'halt') {
        return {
          continue: false,
          user_message: '[OpenBox] HALT: ' + (reason.replace(/^\\[OpenBox\\] /, '') || 'session halted'),
        };
      }
      return {
        continue: false,
        user_message: reason || '[OpenBox] blocked by policy',
      };
    }
    case 'cursor-observe':
      return {};
    case 'none':
      return undefined;
  }
}
`;

function emitBaseSession(verdictModelName: string): string {
  return `// Runtime-portable UUID v4 source. Node ≥19 / Bun / Deno / modern
// browsers / Hermes (RN ≥0.74 / Expo ≥51) all expose
// \`globalThis.crypto.randomUUID()\`; no \`import { randomUUID } from 'crypto'\`
// because that's a Node-only specifier that Metro/RN bundlers can't
// resolve when the SDK is consumed from a mobile app.
function randomUUID(): string {
  if (typeof globalThis.crypto?.randomUUID === 'function') {
    return globalThis.crypto.randomUUID();
  }
  // Fallback for ancient runtimes without Web Crypto. Math.random
  // is fine here; workflow/run/activity IDs need uniqueness, not
  // cryptographic strength (the runtime API key is the auth surface).
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });
}

import type { OpenBoxCoreClient } from '../core-client.js';
import type {
  GovernanceEventPayload,
  GovernanceVerdictResponse,
} from './core-types.js';

type TelemetryEventFields = Pick<
  GovernanceEventPayload,
  | 'session_id'
  | 'llm_model'
  | 'input_tokens'
  | 'output_tokens'
  | 'total_tokens'
  | 'has_tool_calls'
  | 'finish_reason'
  | 'prompt'
  | 'completion'
  | 'tool_name'
  | 'tool_type'
  | 'parent_run_id'
  | 'multi_agent_session_id'
  | 'from_agent_did'
>;

function telemetryEventFields(payload: GovernedPayload): Partial<TelemetryEventFields> {
  return {
    session_id: payload.sessionId,
    llm_model: payload.llmModel,
    input_tokens: payload.inputTokens,
    output_tokens: payload.outputTokens,
    total_tokens: payload.totalTokens,
    has_tool_calls: payload.hasToolCalls,
    finish_reason: payload.finishReason,
    prompt: payload.prompt,
    completion: payload.completion,
    tool_name: payload.toolName,
    tool_type: payload.toolType,
    parent_run_id: payload.parentRunId,
    multi_agent_session_id: payload.multiAgentSessionId,
    from_agent_did: payload.fromAgentDid,
  };
}

/**
 * Construction options for any preset Session class. The \`core\` client
 * is the authenticated transport; the other fields define this workflow
 * run's identity. The runtime owns the lifecycle; Workflow{Started,
 * Completed,Failed} fire automatically on \`govern()\` enter/exit/throw,
 * and via process-exit handlers if the session is still open at exit.
 */
export interface GovernedSessionConfig {
  core: OpenBoxCoreClient;
  /** Stable identifier for this workflow run. */
  workflowId?: string;
  /** Per-attempt run identifier. */
  runId?: string;
  /** Workflow-class identifier surfaced to observability. */
  workflowType?: string;
  /** Originating runtime tag (\`langgraph\` / \`temporal\` / \`mastra\` / ...). */
  taskQueue?: string;
  /** Cross-agent grouping id. Core stores this on the session lifecycle and handoff rows. */
  multiAgentSessionId?: string;
  /**
   * Initial polling interval (ms) when the verdict is \`require_approval\`.
   * The runtime exponentially backs this off (× factor) up to a cap on
   * each attempt so a fast decision doesn't waste a long sleep, but a
   * slow decision doesn't pound core. Default: 500ms.
   */
  approvalPollIntervalMs?: number;
  /**
   * Cap (ms) on the per-attempt poll interval after backoff. Default: 5000ms.
   */
  approvalPollMaxIntervalMs?: number;
  /**
   * Multiplier applied to the poll interval after each attempt. 1.0 = no
   * backoff (fixed interval). Default: 1.5 (gentle exponential).
   */
  approvalPollBackoffFactor?: number;
  /**
   * Random jitter applied to each poll interval as a fraction of the
   * computed interval. 0.25 means ±25%. Default: 0.25. Avoids
   * thundering-herd when a fleet of agents wait on the same approval.
   */
  approvalPollJitter?: number;
  /**
   * @deprecated Accepted as a compatibility no-op. Approval expiration is
   * controlled by the server-owned approval row state.
   */
  approvalMaxWaitMs?: number;
  /**
   * When true, \`runActivity\` skips the in-process poll loop on a
   * \`require_approval\` verdict and returns it straight to the
   * caller. Hook adapters (claude-code, cursor) render that through
   * their \`permission-decision\` verdict shape into
   * \`permissionDecision: 'ask'\`, which pops the host's native
   * permission dialog inline. The local user becomes the approver;
   * external approval clients such as the dashboard, mobile app, or
   * editor extension can still resolve the backend row, but the SDK
   * no longer waits for them. Adapters wire this from the
   * project \`approvalMode\` config (\`inline\` -> true,
   * \`remote\` or unset -> false). Default: false.
   */
  inlineApproval?: boolean;
  /**
   * If true, register process-exit handlers (SIGINT/SIGTERM/uncaughtException
   * /unhandledRejection/beforeExit) that fire \`WorkflowFailed\` best-effort
   * before the process dies. Default: true. Set false for short-lived
   * scripts where the cleanup is wasteful.
   */
  registerExitHandlers?: boolean;
  /**
   * Internal flag set by \`govern.attach()\`. When true, the session starts
   * in the \`opened\` state; \`runActivity\` will NOT auto-fire WorkflowStarted,
   * and explicit \`workflowStarted()\` calls become no-ops (idempotent).
   * The parent process is assumed to have already fired the workflow open
   * event. Don't set this manually; use \`govern.attach()\`.
   */
  attached?: boolean;
  /**
   * Fired the moment the backend returns a \`require_approval\` verdict
   * with an \`approval_id\`; BEFORE pollApproval starts the long wait.
   * Lets harnesses (cursor-hooks, claude-hooks) surface inline approval
   * UI in their host IDE without first waiting through the poll loop.
   * Errors thrown here are swallowed; this hook is observability, not
   * a gate.
   */
  onPendingApproval?: (info: {
    approvalId: string;
    /** Backend's governance_event_id; cross-reference to the Approval row's event_id. */
    governanceEventId?: string;
    activityId: string;
    activityType: string;
    expiresAt?: string;
    reason?: string;
  }) => void | Promise<void>;
  /**
   * Fired when pollApproval resolves (decision came back) OR times out
   * (no decision; arm stays \`require_approval\`). Lets harnesses clear
   * any UI / pending markers they staged in onPendingApproval.
   */
  onApprovalResolved?: (info: {
    approvalId: string;
    activityId: string;
    activityType: string;
    /** 'allow' | 'block' | 'halt' | 'require_approval' (timeout). */
    arm: string;
  }) => void | Promise<void>;
  /**
   * Optional out-of-band decision channel for harnesses that have a
   * faster path than HTTP polling (e.g. a local IPC socket from a UI
   * extension). Called with the same metadata as onPendingApproval and
   * returns a promise that resolves to a final arm when an external
   * source has the decision. The poll loop races this against its
   * normal HTTP cycle and takes whichever finishes first.
   *
   * If the promise rejects or resolves to undefined, the poll loop
   * continues uninterrupted. If it resolves to an arm, the SDK does
   * one confirmatory pollApproval() to read the authoritative verdict
   * from the backend (the external signal might be stale or have
   * arrived in parallel with the backend mutation), then returns.
   */
  awaitExternalDecision?: (info: {
    approvalId: string;
    governanceEventId?: string;
    activityId: string;
    activityType: string;
    expiresAt?: string;
  }) => Promise<'approve' | 'reject' | undefined>;
}

/** Thrown when a session method is called after workflow termination. */
export class SessionAlreadyTerminatedError extends Error {
  constructor() {
    super('[govern] session already terminated; create a new govern() scope to continue.');
    this.name = 'SessionAlreadyTerminatedError';
  }
}

/**
 * Lifecycle-owning base class. Every preset Session class extends this
 * and delegates its public methods to \`runActivity()\`. User code never
 * calls \`begin()\` / \`complete()\` / \`fail()\` directly; the \`govern()\`
 * helper drives them via try/finally.
 */
export class BaseGovernedSession {
  readonly workflowId: string;
  readonly runId: string;
  readonly workflowType: string;
  readonly taskQueue: string;
  readonly multiAgentSessionId?: string;

  protected readonly core: OpenBoxCoreClient;
  private readonly approvalPollIntervalMs: number;
  private readonly approvalPollMaxIntervalMs: number;
  private readonly approvalPollBackoffFactor: number;
  private readonly approvalPollJitter: number;
  private readonly inlineApproval: boolean;
  private opened = false;
  private finalized = false;
  private readonly autoOpenSuppressed: boolean;
  private readonly inFlight = new Set<string>();
  private readonly activityStartsMs = new Map<string, number>();
  private readonly activityParents = new Set<string>();
  private readonly exitHandlerCleanup: Array<() => void> = [];
  protected readonly onPendingApproval?: GovernedSessionConfig['onPendingApproval'];
  protected readonly onApprovalResolved?: GovernedSessionConfig['onApprovalResolved'];
  protected readonly awaitExternalDecision?: GovernedSessionConfig['awaitExternalDecision'];

  constructor(config: GovernedSessionConfig) {
    this.core = config.core;
    this.workflowId = config.workflowId ?? randomUUID();
    this.runId = config.runId ?? randomUUID();
    this.workflowType = config.workflowType ?? 'governed_agent';
    this.taskQueue = config.taskQueue ?? 'generic';
    this.multiAgentSessionId = config.multiAgentSessionId;
    this.approvalPollIntervalMs = config.approvalPollIntervalMs ?? 500;
    this.approvalPollMaxIntervalMs = config.approvalPollMaxIntervalMs ?? 5_000;
    this.approvalPollBackoffFactor = config.approvalPollBackoffFactor ?? 1.5;
    this.approvalPollJitter = config.approvalPollJitter ?? 0.25;
    this.inlineApproval = config.inlineApproval === true;
    this.autoOpenSuppressed = config.attached === true;
    this.onPendingApproval = config.onPendingApproval;
    this.onApprovalResolved = config.onApprovalResolved;
    this.awaitExternalDecision = config.awaitExternalDecision;
    if (config.registerExitHandlers !== false) {
      this.installExitHandlers();
    }
  }

  /** True once \`begin()\` has been called. */
  get isOpen(): boolean {
    return this.opened && !this.finalized;
  }

  /** True after a terminal event (Workflow{Completed,Failed}) fired. */
  get isTerminated(): boolean {
    return this.finalized;
  }

  /**
   * Fire WorkflowStarted. Idempotent; safe to call multiple times,
   * only the first emits. Public so harness-owned consumers (claude-hooks,
   * cursor-hooks) can drive lifecycle when the workflow spans processes.
   * \`govern()\` calls this automatically before the body runs;
   * \`govern.attach()\` does NOT; caller decides when (if ever).
   *
   * Backward-compat alias: \`begin()\`.
   */
  async workflowStarted(): Promise<void> {
    if (this.opened) return;
    this.opened = true;
    await this.emit({ event_type: CANONICAL_EVENT_TYPE.WORKFLOW_STARTED });
  }
  /** @deprecated use \`workflowStarted()\`; same behavior. */
  async begin(): Promise<void> {
    return this.workflowStarted();
  }

  /**
   * Fire WorkflowCompleted. Idempotent. Same public/cross-process
   * rationale as \`workflowStarted\`. \`govern()\` calls this on the
   * happy-path return from the body; \`govern.attach()\` does NOT.
   *
   * Backward-compat alias: \`complete()\`.
   */
  async workflowCompleted(): Promise<${verdictModelName} | undefined> {
    if (this.finalized) return undefined;
    this.finalized = true;
    try {
      return await this.emit({ event_type: CANONICAL_EVENT_TYPE.WORKFLOW_COMPLETED, status: 'completed' });
    } finally {
      this.cleanupExitHandlers();
    }
  }
  /** @deprecated use \`workflowCompleted()\`; same behavior. */
  async complete(): Promise<${verdictModelName} | undefined> {
    return this.workflowCompleted();
  }

  /**
   * Fire WorkflowFailed with an error payload. Idempotent. \`govern()\`
   * calls this if the body throws or if a process-exit handler fires;
   * \`govern.attach()\` does NOT; caller invokes explicitly on harness-
   * signaled session failure.
   *
   * Backward-compat alias: \`fail()\`.
   */
  async workflowFailed(error?: unknown): Promise<${verdictModelName} | undefined> {
    if (this.finalized) return undefined;
    this.finalized = true;
    try {
      return await this.emit({
        event_type: CANONICAL_EVENT_TYPE.WORKFLOW_FAILED,
        status: 'failed',
        error: errorInfoFrom(error),
      });
    } finally {
      this.cleanupExitHandlers();
    }
  }
  /** @deprecated use \`workflowFailed()\`; same behavior. */
  async fail(error?: unknown): Promise<${verdictModelName} | undefined> {
    return this.workflowFailed(error);
  }

  /**
   * Public escape for firing arbitrary (eventType, activityType, payload)
   * tuples beyond what the bound preset's typed methods cover. Used by
   * runtime adapters (claude-hooks / cursor-hooks) when one hook event
   * needs to dispatch to multiple activity_types based on internal
   * routing; e.g. Claude's PreToolUse hook fires FileRead, FileEdit,
   * ShellExecution etc. depending on \`tool_name\`.
   *
   * Mirrors the \`custom\` preset's free-form \`activity()\`. ActivityStarted
   * and ActivityCompleted keep their normal pairing semantics; Handoff and
   * SignalReceived are standalone Core events.
   */
  async activity(
    eventType: 'ActivityStarted' | 'ActivityCompleted' | 'SignalReceived' | 'Handoff',
    activityType: string,
    payload: GovernedPayload,
  ): Promise<${verdictModelName}> {
    return this.runActivity(eventType, activityType, payload);
  }

  /**
   * Observe-only activity emission for post-action hooks. It preserves the
   * same parent-plus-hook span contract as \`activity()\`, but it does not
   * poll approvals or auto-pair ActivityStarted. Use this for host events
   * that cannot block the already-completed action.
   */
  async observeActivity(
    eventType: 'ActivityStarted' | 'ActivityCompleted' | 'SignalReceived' | 'Handoff',
    activityType: string,
    payload: GovernedPayload,
  ): Promise<${verdictModelName}> {
    if (this.finalized) throw new SessionAlreadyTerminatedError();
    if (!this.opened && !this.autoOpenSuppressed) await this.begin();
    const activityId = payload.activityId ?? randomUUID();
    const startTime = payload.startTime ?? Date.now();
    this.inFlight.add(activityId);
    try {
      if (eventType === CANONICAL_EVENT_TYPE.HANDOFF) {
        const handoffVerdict = await this.emit({
          event_type: CANONICAL_EVENT_TYPE.HANDOFF,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          ...telemetryEventFields(payload),
        });
        handoffVerdict.activityId = activityId;
        return handoffVerdict;
      }
      if (eventType === CANONICAL_EVENT_TYPE.SIGNAL_RECEIVED) {
        const signalVerdict = await this.emit({
          event_type: CANONICAL_EVENT_TYPE.SIGNAL_RECEIVED,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          signal_name: payload.signalName,
          signal_args: payload.signalArgs,
          ...telemetryEventFields(payload),
        });
        signalVerdict.activityId = activityId;
        return signalVerdict;
      }
      if (eventType === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED) {
        this.activityStartsMs.set(activityId, startTime);
        const startedVerdict = await this.emitWithSpanHook({
          event_type: CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          start_time: startTime,
          spans: payload.spans as unknown as GovernanceEventPayload['spans'],
          ...telemetryEventFields(payload),
        });
        startedVerdict.activityId = activityId;
        return startedVerdict;
      }
      return this.emitCompleted(activityId, activityType, observeCompletedSpanPayload(payload), {
        pollApprovals: false,
      });
    } finally {
      this.inFlight.delete(activityId);
    }
  }

  /**
   * Split-stage activity for callers that must run business logic between
   * the input gate and the output gate (e.g. governed tools that gate the
   * produced artifact). Emits ActivityStarted and returns the gate verdict
   * plus a \`complete()\` bound to the same activity id, so the pair cannot
   * drift apart. Stopped starts (block/halt) are canonically left
   * unpaired. Remote approvals are resolved before returning so the
   * caller only runs business logic after an allow/block/halt decision;
   * inline/defer approvals still return \`require_approval\` for the host
   * native dialog path.
   */
  async openActivity(
    activityType: string,
    payload: GovernedPayload,
  ): Promise<{
    activityId: string;
    verdict: ${verdictModelName};
    complete(
      payload: GovernedPayload,
      completionActivityType?: string,
    ): Promise<${verdictModelName}>;
  }> {
    if (this.finalized) throw new SessionAlreadyTerminatedError();
    if (!this.opened && !this.autoOpenSuppressed) await this.begin();
    const activityId = payload.activityId ?? randomUUID();
    const startTime = payload.startTime ?? Date.now();
    this.activityStartsMs.set(activityId, startTime);
    this.inFlight.add(activityId);
    try {
      let verdict = await this.emitWithSpanHook({
        event_type: CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
        activity_id: activityId,
        activity_type: activityType,
        activity_input: payload.input,
        start_time: startTime,
        spans: payload.spans as unknown as GovernanceEventPayload['spans'],
        ...telemetryEventFields(payload),
      });
      verdict.activityId = activityId;
      if (verdict.arm === 'require_approval') {
        const approvalId = verdict.approvalId ?? activityId;
        if (this.onPendingApproval) {
          try {
            await this.onPendingApproval({
              approvalId,
              governanceEventId: verdict.governanceEventId,
              activityId,
              activityType,
              expiresAt: verdict.approvalExpiresAt,
              reason: verdict.reason,
            });
          } catch { /* observability hook; never blocks */ }
        }
        if (!this.inlineApproval) {
          verdict = await this.pollApproval(activityId, activityType, verdict);
          verdict.activityId = activityId;
          if (this.onApprovalResolved) {
            try {
              await this.onApprovalResolved({
                approvalId,
                activityId,
                activityType,
                arm: verdict.arm,
              });
            } catch { /* observability hook */ }
          }
        }
      }
      if (verdict.arm !== 'allow' && verdict.arm !== 'constrain') {
        this.activityStartsMs.delete(activityId);
        this.activityParents.delete(activityId);
      }
      return {
        activityId,
        verdict,
        complete: (completionPayload, completionActivityType) =>
          this.runActivity(
            CANONICAL_EVENT_TYPE.ACTIVITY_COMPLETED,
            completionActivityType ?? activityType,
            {
              ...completionPayload,
              activityId,
              hookSpanParentEventType: completionPayload.hookSpanParentEventType ?? CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
            },
          ),
      };
    } finally {
      this.inFlight.delete(activityId);
    }
  }

  /**
   * Run one activity through the canonical envelope. Preset classes
   * call this with their fixed (eventType, activityType) tuple; the
   * \`custom\` preset takes them from the user.
   *
   * Strategy depends on \`eventType\`:
   *   ActivityStarted   → emit start; pre-stage block → no completion fired.
   *                       Otherwise emit a paired ActivityCompleted.
   *   ActivityCompleted → emit completion only (post-stage observe / gate).
   *   SignalReceived    → fire-and-forget telemetry (no gate).
   *   Handoff           → emit Core handoff row (no activity pair, no gate).
   */
  protected async runActivity(
    eventType: 'ActivityStarted' | 'ActivityCompleted' | 'SignalReceived' | 'Handoff',
    activityType: string,
    payload: GovernedPayload,
  ): Promise<${verdictModelName}> {
    if (this.finalized) throw new SessionAlreadyTerminatedError();
    if (!this.opened && !this.autoOpenSuppressed) await this.begin();
    const activityId = payload.activityId ?? randomUUID();
    const startTime = payload.startTime ?? Date.now();
    this.inFlight.add(activityId);

    try {
      if (eventType === CANONICAL_EVENT_TYPE.HANDOFF) {
        const handoffVerdict = await this.emit({
          event_type: CANONICAL_EVENT_TYPE.HANDOFF,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          ...telemetryEventFields(payload),
        });
        handoffVerdict.activityId = activityId;
        return handoffVerdict;
      }

      if (eventType === CANONICAL_EVENT_TYPE.SIGNAL_RECEIVED) {
        const signalVerdict = await this.emit({
          event_type: CANONICAL_EVENT_TYPE.SIGNAL_RECEIVED,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          signal_name: payload.signalName,
          signal_args: payload.signalArgs,
          ...telemetryEventFields(payload),
        });
        signalVerdict.activityId = activityId;
        return signalVerdict;
      }

      if (eventType === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED) {
        this.activityStartsMs.set(activityId, startTime);
        const startedVerdict = await this.emitWithSpanHook({
          event_type: CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
          activity_id: activityId,
          activity_type: activityType,
          activity_input: payload.input,
          start_time: startTime,
          spans: payload.spans as unknown as GovernanceEventPayload['spans'],
          ...telemetryEventFields(payload),
        });
        startedVerdict.activityId = activityId;
        if (startedVerdict.arm === 'constrain') {
          // Spec: \`constrain\` means the action proceeds with the
          // transformed payload, so the start is paired like an allow.
          // The started verdict (carrying the guardrails transform) is
          // returned; the paired completion is lifecycle bookkeeping.
          try {
            await this.emitCompleted(activityId, activityType, { ...payload, spans: undefined });
          } catch { /* pairing must not mask the constrain verdict */ }
          return startedVerdict;
        }
        if (startedVerdict.arm !== 'allow') {
          this.activityStartsMs.delete(activityId);
          this.activityParents.delete(activityId);
          // Pre-stage block; never emit ActivityCompleted, but if the
          // gate said require_approval, poll for the approval decision.
          // pollApproval keys on workflow_id + run_id + activity_id;
          // approval_id is informational. Some backends omit it from
          // /governance/evaluate responses (only return governance_event_id);
          // gating on approvalId there silently skips polling and the
          // user sees an instant "approval pending" message that never
          // resolves even when the dashboard click lands.
          if (startedVerdict.arm === 'require_approval') {
            const approvalId = startedVerdict.approvalId ?? activityId;
            if (this.onPendingApproval) {
              try {
                await this.onPendingApproval({
                  approvalId,
                  governanceEventId: startedVerdict.governanceEventId,
                  activityId,
                  activityType,
                  expiresAt: startedVerdict.approvalExpiresAt,
                  reason: startedVerdict.reason,
                });
              } catch { /* observability hook; never blocks */ }
            }
            // Inline-approval mode: skip the poll loop and return the
            // require_approval verdict straight to the caller. The
            // hook adapter renders permissionDecision:'ask' so the
            // host's native dialog pops inline. The backend row stays
            // pending until a remote approver resolves it or it
            // expires; on the inline path the local user decides via
            // the TUI.
            if (this.inlineApproval) {
              return startedVerdict;
            }
            const polled = await this.pollApproval(activityId, activityType, startedVerdict);
            polled.activityId = activityId;
            if (this.onApprovalResolved) {
              try {
                await this.onApprovalResolved({
                  approvalId,
                  activityId,
                  activityType,
                  arm: polled.arm,
                });
              } catch { /* observability hook */ }
            }
            return polled;
          }
          return startedVerdict;
        }
        // Allow → emit the matching ActivityCompleted with the payload's
        // output (or undefined if the user only has input at start time).
        return this.emitCompleted(activityId, activityType, { ...payload, spans: undefined });
      }

      // eventType === ActivityCompleted; post-stage gate.
      return this.emitCompleted(activityId, activityType, payload);
    } finally {
      this.inFlight.delete(activityId);
    }
  }

  private async emitCompleted(
    activityId: string,
    activityType: string,
    payload: GovernedPayload,
    options: { pollApprovals?: boolean } = {},
  ): Promise<${verdictModelName}> {
    const startTime = payload.startTime ?? this.activityStartsMs.get(activityId);
    const endTime = payload.endTime ?? Date.now();
    const durationMs =
      payload.durationMs ??
      (typeof startTime === 'number' ? Math.max(0, endTime - startTime) : undefined);
    const completedVerdict = await this.emitWithSpanHook({
      event_type: CANONICAL_EVENT_TYPE.ACTIVITY_COMPLETED,
      activity_id: activityId,
      activity_type: activityType,
      status: activityCompletionStatus(activityType),
      activity_input: payload.input,
      activity_output: payload.output,
      start_time: startTime,
      end_time: endTime,
      duration_ms: durationMs,
      spans: payload.spans as unknown as GovernanceEventPayload['spans'],
      hook_span_parent_event_type: payload.hookSpanParentEventType,
      ensure_hook_span_parent: payload.ensureHookSpanParent,
      ...telemetryEventFields(payload),
    });
    this.activityStartsMs.delete(activityId);
    this.activityParents.delete(activityId);
    completedVerdict.activityId = activityId;
    if (completedVerdict.arm === 'require_approval' && options.pollApprovals !== false) {
      // See comment in runActivity: poll on activity_id even if the
      // backend omitted approval_id in the evaluate response.
      const approvalId = completedVerdict.approvalId ?? activityId;
      if (this.onPendingApproval) {
        try {
          await this.onPendingApproval({
            approvalId,
            governanceEventId: completedVerdict.governanceEventId,
            activityId,
            activityType,
            expiresAt: completedVerdict.approvalExpiresAt,
            reason: completedVerdict.reason,
          });
        } catch { /* observability */ }
      }
      if (this.inlineApproval) {
        // Inline mode: skip poll, return the require_approval
        // verdict unchanged so the renderer emits permissionDecision:'ask'.
        return completedVerdict;
      }
      const polled = await this.pollApproval(activityId, activityType, completedVerdict);
      polled.activityId = activityId;
      if (this.onApprovalResolved) {
        try {
          await this.onApprovalResolved({ approvalId, activityId, activityType, arm: polled.arm });
        } catch { /* observability */ }
      }
      return polled;
    }
    return completedVerdict;
  }

  private async emitWithSpanHook(
    event: Pick<
      GovernanceEventPayload,
      'event_type' | 'activity_id' | 'activity_type' | 'activity_input' | 'activity_output' | 'status' | 'error' | 'attempt' | 'spans' | 'signal_name' | 'signal_args' | 'start_time' | 'end_time' | 'duration_ms' | keyof TelemetryEventFields
    > & {
      hook_span_parent_event_type?: typeof CANONICAL_EVENT_TYPE.ACTIVITY_STARTED;
      ensure_hook_span_parent?: boolean;
    },
  ): Promise<${verdictModelName}> {
    const hasActivitySpans =
      (event.event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED || event.hook_span_parent_event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED) &&
      Array.isArray(event.spans) &&
      event.spans.some(isPersistableHookSpan);
    const parentEvent = withoutSpanRuntimeHints({ ...event, spans: undefined }) as typeof event;
    const hookParentEvent = event.hook_span_parent_event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED
      ? ({
          ...parentEvent,
          event_type: CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
          status: undefined,
          activity_output: undefined,
          end_time: undefined,
          duration_ms: undefined,
        } as typeof event)
      : parentEvent;
    if (
      hasActivitySpans &&
      hookParentEvent.event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED &&
      event.ensure_hook_span_parent === true &&
      event.activity_id &&
      !this.activityParents.has(event.activity_id)
    ) {
      await this.emit(withoutSpanRuntimeHints(hookParentEvent));
      this.activityParents.add(event.activity_id);
      if (typeof event.start_time === 'number') {
        this.activityStartsMs.set(event.activity_id, event.start_time);
      }
    }
    const parentVerdict = await this.emit(parentEvent);
    if (parentEvent.event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED && event.activity_id) {
      this.activityParents.add(event.activity_id);
    }
    if (!hasActivitySpans) return parentVerdict;

    let hookVerdict = parentVerdict;
    const persistableSpans = (event.spans ?? []).filter(isPersistableHookSpan);
    for (const span of persistableSpans) {
      const hookSpan = withSpanHookContext(span, event);
      hookVerdict = stricterVerdict(hookVerdict, await this.emit({
        ...hookParentEvent,
        attempt: event.attempt ?? 1,
        hook_trigger: true,
        spans: [hookSpan],
      } as typeof event & { hook_trigger: true }));
    }
    if (parentVerdict.arm !== 'allow' && parentVerdict.arm !== 'constrain') {
      return parentVerdict;
    }
    return hookVerdict;
  }

  private async emit(
    event: Pick<
      GovernanceEventPayload,
      'event_type' | 'activity_id' | 'activity_type' | 'activity_input' | 'activity_output' | 'status' | 'error' | 'attempt' | 'spans' | 'signal_name' | 'signal_args' | 'start_time' | 'end_time' | 'duration_ms' | keyof TelemetryEventFields
    > & { hook_trigger?: boolean },
  ): Promise<${verdictModelName}> {
    const payload = {
      ...event,
      source: 'workflow-telemetry',
      workflow_id: this.workflowId,
      run_id: this.runId,
      workflow_type: this.workflowType,
      task_queue: this.taskQueue,
      multi_agent_session_id: event.multi_agent_session_id ?? this.multiAgentSessionId,
      timestamp: new Date().toISOString(),
      hook_trigger: event.hook_trigger ?? false,
    } as unknown as GovernanceEventPayload;
    if (Array.isArray(event.spans)) {
      payload.span_count = event.spans.length;
    } else {
      delete payload.spans;
    }
    const response = await this.core.evaluate(payload);
    return mapVerdict(response);
  }

  private async pollApproval(
    activityId: string,
    activityType: string,
    initial: ${verdictModelName},
  ): Promise<${verdictModelName}> {
    // ── Polling design notes ──
    // Server-owned approval expiration. This matches the Python LangGraph
    // SDK contract: the server controls approval expiration and the SDK
    // does not convert locally elapsed timestamps into terminal verdicts.
    // Exponential backoff (× factor each attempt, capped at maxIntervalMs)
    // matches the bimodal latency of approvals (decided in seconds OR
    // minutes) without burning a long sleep when the answer's right there.
    // ±jitter randomizes per-attempt delay so a fleet of agents waiting
    // on the same approval window doesn't thunder-herd the API in
    // lockstep.
    //
    // If the harness provides \`awaitExternalDecision\`, we race that
    // promise against the poll loop. The external signal (e.g. a local
    // IPC socket push) typically arrives orders of magnitude faster
    // than the next HTTP tick; when it does, we exit the sleep early
    // and run one confirmatory pollApproval() to fetch the backend's
    // authoritative verdict for this activity_id.
    const approvalId = initial.approvalId ?? activityId;
    let externalPending = this.awaitExternalDecision !== undefined;
    let externalSignaled = false;
    const externalDecision = this.awaitExternalDecision
      ? this.awaitExternalDecision({
          approvalId,
          governanceEventId: initial.governanceEventId,
          activityId,
          activityType,
          expiresAt: initial.approvalExpiresAt,
        }).then(
          (d) => {
            externalSignaled = d === 'approve' || d === 'reject';
            externalPending = false;
            return d;
          },
          () => {
            externalPending = false;
            return undefined;
          },
        )
      : undefined;

    let nextInterval = this.approvalPollIntervalMs;
    while (true) {
      const jittered = applyJitter(nextInterval, this.approvalPollJitter);
      // Wake early if an external decision arrives.
      const sleepMs = Math.max(0, jittered);
      if (externalPending && externalDecision) {
        await Promise.race([sleep(sleepMs), externalDecision]);
      } else {
        await sleep(sleepMs);
      }
      let status: Awaited<ReturnType<OpenBoxCoreClient['pollApproval']>>;
      try {
        status = await this.core.pollApproval({
          workflow_id: this.workflowId,
          run_id: this.runId,
          activity_id: activityId,
        });
      } catch {
        nextInterval = externalSignaled
          ? this.approvalPollIntervalMs
          : Math.min(
              nextInterval * this.approvalPollBackoffFactor,
              this.approvalPollMaxIntervalMs,
            );
        continue;
      }
      const statusWithExpiry = status as typeof status & { expired?: boolean };
      if (statusWithExpiry.expired === true) {
        return {
          arm: 'block',
          approvalId: initial.approvalId,
          governanceEventId: initial.governanceEventId,
          approvalExpiresAt: status.approval_expiration_time,
          reason: status.reason ?? \`Approval expired for \${activityType}\`,
          riskScore: initial.riskScore,
          trustTier: initial.trustTier,
        };
      }
      const approvalArm = (status as typeof status & {
        verdict?: string | number;
      }).verdict ?? status.action;
      const normalizedApprovalArm =
        approvalArm === undefined ? undefined : normalizeArm(approvalArm);
      if (
        normalizedApprovalArm === 'allow' ||
        normalizedApprovalArm === 'block' ||
        normalizedApprovalArm === 'halt'
      ) {
        return {
          arm: normalizedApprovalArm,
          approvalId: initial.approvalId,
          governanceEventId: initial.governanceEventId,
          approvalExpiresAt: status.approval_expiration_time,
          reason: status.reason,
          riskScore: initial.riskScore,
          trustTier: initial.trustTier,
        };
      }
      // Core may return require_approval or constrain while the approval row is still pending.
      // External signal said "decided" but backend hasn't caught up
      // yet (mutation in flight). Tighten the cadence to catch it
      // promptly instead of waiting for the next backoff step.
      nextInterval = externalSignaled
        ? this.approvalPollIntervalMs
        : Math.min(
            nextInterval * this.approvalPollBackoffFactor,
            this.approvalPollMaxIntervalMs,
          );
    }
  }

  /**
   * Best-effort handlers for process death. SIGINT/SIGTERM/uncaught
   * exceptions get a brief async window to fire WorkflowFailed; \`exit\`
   * is synchronous-only so we just log a warning. Multiple sessions in
   * the same process each register their own handlers; cleanup on
   * normal completion removes them.
   */
  private installExitHandlers(): void {
    if (typeof process === 'undefined' || !process.on) return;

    const failOnSignal = (reason: string) => async () => {
      if (this.finalized) return;
      try {
        await Promise.race([
          this.fail(new Error(\`process_exit:\${reason}\`)),
          sleep(2_000),
        ]);
      } catch {
        // best-effort
      }
    };

    const sigint = failOnSignal('SIGINT');
    const sigterm = failOnSignal('SIGTERM');
    const beforeExit = failOnSignal('beforeExit');
    const uncaught = (err: unknown) => {
      void failOnSignal('uncaughtException')();
    };
    const unhandled = (err: unknown) => {
      void failOnSignal('unhandledRejection')();
    };

    process.on('SIGINT', sigint);
    process.on('SIGTERM', sigterm);
    process.on('beforeExit', beforeExit);
    process.on('uncaughtException', uncaught);
    process.on('unhandledRejection', unhandled);

    this.exitHandlerCleanup.push(() => {
      process.removeListener('SIGINT', sigint);
      process.removeListener('SIGTERM', sigterm);
      process.removeListener('beforeExit', beforeExit);
      process.removeListener('uncaughtException', uncaught);
      process.removeListener('unhandledRejection', unhandled);
    });
  }

  private cleanupExitHandlers(): void {
    for (const fn of this.exitHandlerCleanup) {
      try { fn(); } catch { /* ignore */ }
    }
    this.exitHandlerCleanup.length = 0;
  }
}

function withoutSpanRuntimeHints<T extends Record<string, unknown>>(event: T): T {
  const next = { ...event };
  delete next.hook_span_parent_event_type;
  delete next.ensure_hook_span_parent;
  return next;
}

function observeCompletedSpanPayload(payload: GovernedPayload): GovernedPayload {
  if (!Array.isArray(payload.spans) || payload.spans.length === 0) return payload;
  if (payload.hookSpanParentEventType) return payload;
  return {
    ...payload,
    hookSpanParentEventType: CANONICAL_EVENT_TYPE.ACTIVITY_STARTED,
    ensureHookSpanParent: payload.ensureHookSpanParent ?? true,
  };
}

function activityCompletionStatus(activityType: string): 'completed' | 'failed' {
  return /(error|fail|failed|failure|timeout|timedout|cancel|abort)/i.test(activityType)
    ? 'failed'
    : 'completed';
}

function toolActivityTypeFromPayload(payload: GovernedPayload): string {
  const direct = namedToolFromRecord(payload as unknown);
  if (direct) return direct;

  for (const item of payload.input ?? []) {
    const name = namedToolFromRecord(item);
    if (name) return name;
  }

  return 'AgentAction';
}

function namedToolFromRecord(value: unknown): string | undefined {
  if (!value || typeof value !== 'object') return undefined;
  const record = value as Record<string, unknown>;
  const direct = firstNonEmptyString(
    record.toolName,
    record.tool_name,
    record.tool,
    record.name,
  );
  if (direct) return direct;

  return (
    namedToolFromRecord(record.toolCall) ??
    namedToolFromRecord(record.tool_call) ??
    namedToolFromRecord(record.call) ??
    namedToolFromRecord(record.args)
  );
}

function firstNonEmptyString(...values: unknown[]): string | undefined {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return undefined;
}
`;
}

function literalTs(value: unknown): string {
  return JSON.stringify(value, null, 2);
}

function arrayOfStrings(value: unknown): string[] {
  return Array.isArray(value)
    ? value.filter((entry): entry is string => typeof entry === 'string')
    : [];
}

function arrayOfRecords(value: unknown): Record<string, unknown>[] {
  return Array.isArray(value)
    ? value.filter(
        (entry): entry is Record<string, unknown> =>
          entry !== null && typeof entry === 'object' && !Array.isArray(entry),
      )
    : [];
}

function uniqueStrings(values: string[]): string[] {
  return [...new Set(values)];
}

/**
 * Emit one Session class per @preset interface. Each method on the
 * preset routes through `BaseGovernedSession.runActivity()` with its
 * fixed (eventType, activityType) tuple; the lifecycle invariants
 * ride for free.
 *
 * The `custom` preset is special: its `activity()` operation takes
 * (activityType, stage, payload) so the user supplies them at call
 * time. Stage `pre` → ActivityStarted, `post` → ActivityCompleted.
 */
function emitPresetSession(p: PresetEntry, verdictModelName: string): string {
  const sessionName = `${p.pascal}Session`;
  if (p.isCustom) {
    return `/** Free-form session; caller supplies activity_type + stage at call time. */
export class ${sessionName} extends BaseGovernedSession {
  /**
   * Run an arbitrary activity. The runtime stamps:
   *   stage="pre"  → event_type=ActivityStarted
   *   stage="post" → event_type=ActivityCompleted
   */
  async activity(
    activityType: string,
    stage: ActivityStage,
    payload: GovernedPayload,
  ): Promise<${verdictModelName}> {
    const eventType = stage === 'pre' ? 'ActivityStarted' : 'ActivityCompleted';
    return this.runActivity(eventType, activityType, payload);
  }
}`;
  }

  const methods = p.methods
    .map((m) => {
      const eventType = JSON.stringify(m.eventType);
      const activityType = activityTypeExpression(m.activityType, m.name);
      return `  async ${m.name}(payload: GovernedPayload): Promise<${verdictModelName}> {
    return this.runActivity(${eventType}, ${activityType}, payload);
  }`;
    })
    .join('\n\n');

  return `/** Session for the \`${p.name}\` preset; methods match the framework's hook names. */
export class ${sessionName} extends BaseGovernedSession {
${methods}
}`;
}

function activityTypeExpression(
  activityType: string | undefined,
  fallback: string,
): string {
  const resolved = activityType ?? fallback;
  if (resolved === 'on_tool_start' || resolved === 'on_tool_end') {
    return 'toolActivityTypeFromPayload(payload)';
  }
  return JSON.stringify(resolved);
}

/**
 * Emit the `presets` registry; maps every camelCase preset name to
 * its Session constructor. Users do `presets.claudeCode` and get the
 * right class.
 */
function emitPresetsRegistry(presets: PresetEntry[]): string {
  const entries = presets
    .map((p) => `  ${p.camel}: ${p.pascal}Session,`)
    .join('\n');
  return `/**
 * Registry of every framework preset. Pass one as \`config.preset\` to
 * \`govern()\` and the typed session inside the callback will match.
 *
 * \`\`\`ts
 * await govern({ core, preset: presets.claudeCode }, async (session) => {
 *   await session.preToolUse({ input: [...] });
 * });
 * \`\`\`
 */
export const presets = {
${entries}
} as const;

export type Presets = typeof presets;
export type PresetCtor = Presets[keyof Presets];`;
}

/**
 * Emit the public `govern<S>()` helper. Generic over a preset class so
 * the session inside the callback gets the matching typed methods.
 */
function emitGovernHelper(verdictModelName: string): string {
  return `/**
 * Open a workflow envelope, run \`body\` with the typed session, and
 * finalize (Workflow{Completed,Failed}) on return; even if \`body\`
 * throws. Process-exit handlers fire WorkflowFailed best-effort if the
 * runtime dies mid-session.
 *
 * For single-process consumers (mobile, extension, MCP, custom Node).
 * For cross-process / harness-owned workflows (claude-hooks, cursor-hooks)
 * use \`govern.attach()\` instead.
 *
 * \`\`\`ts
 * await govern({ core, preset: presets.claudeCode }, async (session) => {
 *   await session.preToolUse({ input: [...] });
 * });
 * \`\`\`
 */
export async function govern<S extends PresetCtor, T>(
  config: GovernedSessionConfig & { preset: S },
  body: (session: InstanceType<S>) => Promise<T>,
): Promise<T> {
  const { preset: Ctor, ...sessionConfig } = config;
  const session = new Ctor(sessionConfig) as InstanceType<S>;
  try {
    await (session as unknown as BaseGovernedSession).workflowStarted();
    const result = await body(session);
    await (session as unknown as BaseGovernedSession).workflowCompleted();
    return result;
  } catch (err) {
    await (session as unknown as BaseGovernedSession).workflowFailed(err);
    throw err;
  }
}

/**
 * Attach a session to an existing workflow. For consumers where the
 * harness (Claude Code, Cursor, an external orchestrator) owns the
 * workflow lifecycle and the consumer fires individual activity events
 * across many short-lived processes.
 *
 * Differences vs \`govern()\`:
 *   - No auto-WorkflowStarted (caller fires \`session.workflowStarted()\`
 *     explicitly when the harness signals session start).
 *   - No auto-WorkflowCompleted (caller fires it on session end).
 *   - No process-exit handlers by default (a fresh process per hook is
 *     normal flow, not workflow failure).
 *   - \`workflowId\` and \`runId\` are REQUIRED on the config; the harness
 *     persists them across processes.
 *
 * \`\`\`ts
 * const session = govern.attach({
 *   core, agentId,
 *   preset: presets.claudeCode,
 *   workflowId, runId,         // read from your harness's session store
 * });
 *
 * if (firstHookInSession) await session.workflowStarted();
 * const verdict = await session.preToolUse({ input: [...] });
 * if (lastHookInSession) await session.workflowCompleted();
 * \`\`\`
 */
function governAttach<S extends PresetCtor>(
  config: Omit<GovernedSessionConfig, 'workflowId' | 'runId' | 'registerExitHandlers'> & {
    preset: S;
    workflowId: string;
    runId: string;
    /** Default \`false\`; fresh-process-per-hook is normal flow, not failure. */
    registerExitHandlers?: boolean;
  },
): InstanceType<S> {
  const { preset: Ctor, ...rest } = config;
  return new Ctor({
    ...rest,
    registerExitHandlers: rest.registerExitHandlers ?? false,
    attached: true,
  }) as InstanceType<S>;
}

// Namespace merge so consumers see \`govern.attach(...)\` typed.
// eslint-disable-next-line @typescript-eslint/no-namespace
export namespace govern {
  export const attach = governAttach;
}
`;
}

/** Verdict-mapping helpers shared across all preset session classes. */
function emitVerdictHelpers(verdictModelName: string): string {
  return `function mapVerdict(response: GovernanceVerdictResponse): ${verdictModelName} {
  const raw = response as GovernanceVerdictResponse & {
    approvalId?: string;
    governanceEventId?: string;
    approvalExpiresAt?: string;
    riskScore?: number;
    trustTier?: number;
    alignmentScore?: number;
    policyId?: string;
    behavioralViolations?: string[];
    fallbackUsed?: boolean;
    guardrailsResult?: GovernanceVerdictResponse['guardrails_result'];
    ageResult?: GovernanceVerdictResponse['age_result'];
  };
  const wireArm = normalizeArm(response.verdict ?? response.action ?? 'allow');
  const guardrailsResult = mapGuardrailsResult(response.guardrails_result ?? raw.guardrailsResult);
  const guardrailsFailed = guardrailsResult?.validationPassed === false;
  const arm =
    wireArm === 'halt' || wireArm === 'block'
      ? wireArm
      : guardrailsFailed
        ? 'block'
        : wireArm;
  return {
    arm,
    approvalId: response.approval_id ?? raw.approvalId,
    // Cross-reference key for matching this verdict against the
    // backend's persisted Approval row (whose \`event_id\` field equals
    // the response's \`governance_event_id\`). The backend currently
    // omits \`approval_id\` from /governance/evaluate responses, so this
    // is the one stable identifier consumers can use to dedup against
    // the dashboard's pending-approvals list.
    governanceEventId: (response as { governance_event_id?: string }).governance_event_id ?? raw.governanceEventId,
    approvalExpiresAt: response.approval_expiration_time ?? raw.approvalExpiresAt,
    reason: response.reason ?? (guardrailsFailed ? guardrailFailureReason(guardrailsResult) : undefined),
    riskScore: response.risk_score ?? raw.riskScore ?? 0,
    trustTier: response.trust_tier ?? raw.trustTier ?? undefined,
    alignmentScore: response.alignment_score ?? raw.alignmentScore,
    policyId: response.policy_id ?? raw.policyId,
    behavioralViolations: response.behavioral_violations ?? raw.behavioralViolations,
    constraints: response.constraints,
    metadata: response.metadata,
    fallbackUsed: response.fallback_used ?? raw.fallbackUsed,
    guardrailsResult,
    ageResult: response.age_result ?? raw.ageResult,
  };
}

function guardrailFailureReason(result: GuardrailsVerdict | undefined): string {
  if (!result) return 'Guardrails validation failed';
  const reasons = result.reasons
    .map((reason) => cleanGuardrailReason(reason.reason))
    .filter((reason) => reason.length > 0);
  if (reasons.length > 0) {
    return result.inputType === 'activity_output' ? reasons.join('; ') : reasons[0];
  }
  return result.inputType === 'activity_output'
    ? 'Guardrails output validation failed'
    : 'Guardrails validation failed';
}

function cleanGuardrailReason(reason: string): string {
  const withoutQuestion = reason.replace(/\\n?-\\s*Question:\\s*\\[Session context\\][^\\n]*\\n?/g, '');
  for (const marker of ['\\n\\nThought:', '\\n\\nThought', '\\nThought:', '\\nThought']) {
    const index = withoutQuestion.indexOf(marker);
    if (index >= 0) return withoutQuestion.slice(0, index).trimEnd();
  }
  return withoutQuestion.trimEnd();
}

function mapGuardrailsResult(
  raw: GovernanceVerdictResponse['guardrails_result'],
): GuardrailsVerdict | undefined {
  if (!raw) return undefined;
  if (Object.keys(raw as unknown as Record<string, unknown>).length === 0) return undefined;
  return {
    inputType: normalizeGuardrailsInputType(raw.input_type),
    redactedInput: raw.redacted_input,
    redactedOutput: (raw as typeof raw & { redacted_output?: unknown; redactedOutput?: unknown }).redacted_output
      ?? (raw as typeof raw & { redacted_output?: unknown; redactedOutput?: unknown }).redactedOutput,
    validationPassed: raw.validation_passed !== false,
    rawLogs: raw.raw_logs,
    reasons: ((raw.reasons ?? []) as Array<{ type?: string; field?: string; reason?: string }>).map((r) => ({
      type: String(r.type ?? ''),
      field: r.field,
      reason: String(r.reason ?? ''),
    })),
    fieldResults: [
      ...(((raw as typeof raw & { field_results?: Array<{ field?: string; status?: string; reason?: string }>; fieldResults?: Array<{ field?: string; status?: string; reason?: string }> }).field_results
        ?? (raw as typeof raw & { field_results?: Array<{ field?: string; status?: string; reason?: string }>; fieldResults?: Array<{ field?: string; status?: string; reason?: string }> }).fieldResults
        ?? []) as Array<{ field?: string; status?: string; reason?: string }>),
      ...((raw.results ?? []) as Array<{ results?: Array<{ field?: string; status?: string; reason?: string }> }>)
        .flatMap((g) => g.results ?? []),
    ].map((fr) => ({
        field: String(fr.field ?? ''),
        status: normalizeGuardrailFieldStatus(fr.status),
        reason: fr.reason,
      })),
  };
}

function normalizeGuardrailsInputType(value: string | undefined): GuardrailsVerdict['inputType'] {
  switch (value) {
    case 'activity_output':
      return 'activity_output';
    case 'signal_args':
      return 'signal_args';
    case 'activity_input':
    default:
      return 'activity_input';
  }
}

function normalizeGuardrailFieldStatus(value: string | undefined): 'allowed' | 'blocked' | 'redacted' | 'transformed' | 'skipped' {
  switch (value) {
    case 'allowed':
    case 'allow':
      return 'allowed';
    case 'blocked':
    case 'block':
      return 'blocked';
    case 'redacted':
      return 'redacted';
    case 'transformed':
      return 'transformed';
    case 'skipped':
    default:
      return 'skipped';
  }
}

function normalizeArm(value: string | number | undefined): VerdictArm {
  if (typeof value === 'number') {
    switch (value) {
      case 1:
        return 'constrain';
      case 2:
        return 'require_approval';
      case 3:
        return 'block';
      case 4:
        return 'halt';
      case 0:
      default:
        return 'allow';
    }
  }
  const normalized =
    typeof value === 'string'
      ? value.trim().toLowerCase().replace(/-/g, '_')
      : value;
  switch (normalized) {
    case 'approve':
    case 'approved':
    case 'allow':
    case 'allowed':
    case 'continue':
      return 'allow';
    case 'constrain':
      return 'constrain';
    case 'require_approval':
    case 'requires_approval':
    case 'request_approval':
    case 'pending':
    case 'ask':
      return 'require_approval';
    case 'reject':
    case 'rejected':
    case 'deny':
    case 'denied':
    case 'block':
    case 'blocked':
      return 'block';
    case 'halt':
    case 'stopped':
    case 'stop':
      return 'halt';
    default:
      return 'allow';
  }
}

function verdictRank(arm: VerdictArm): number {
  switch (arm) {
    case 'halt':
      return 4;
    case 'block':
      return 3;
    case 'require_approval':
      return 2;
    case 'constrain':
      return 1;
    case 'allow':
    default:
      return 0;
  }
}

function stricterVerdict(
  base: WorkflowVerdict,
  hook: WorkflowVerdict,
): WorkflowVerdict {
  const hookRank = verdictRank(hook.arm);
  const baseRank = verdictRank(base.arm);
  if (hookRank > baseRank) return hook;
  if (hookRank < baseRank) return base;
  return mergePeerVerdicts(base, hook);
}

function mergePeerVerdicts(
  base: WorkflowVerdict,
  hook: WorkflowVerdict,
): WorkflowVerdict {
  return {
    ...hook,
    ...base,
    riskScore: Math.max(base.riskScore ?? 0, hook.riskScore ?? 0),
    trustTier: base.trustTier ?? hook.trustTier,
    alignmentScore: base.alignmentScore ?? hook.alignmentScore,
    policyId: base.policyId ?? hook.policyId,
    behavioralViolations: base.behavioralViolations ?? hook.behavioralViolations,
    constraints: base.constraints ?? hook.constraints,
    metadata: hook.metadata || base.metadata
      ? { ...(hook.metadata ?? {}), ...(base.metadata ?? {}) }
      : undefined,
    fallbackUsed: base.fallbackUsed ?? hook.fallbackUsed,
    guardrailsResult: base.guardrailsResult ?? hook.guardrailsResult,
    ageResult: base.ageResult ?? hook.ageResult,
  };
}

function isPersistableHookSpan(span: unknown): boolean {
  if (!span || typeof span !== 'object') return false;
  const record = span as Record<string, unknown>;
  if (hasNonEmptyString(record, 'semantic_type', 'semanticType')) {
    return true;
  }
  if (hasNonEmptyString(record, 'hook_type', 'hookType')) {
    return true;
  }
  const attributes =
    record.attributes && typeof record.attributes === 'object'
      ? (record.attributes as Record<string, unknown>)
      : {};
  return (
    hasNonEmptyString(record, 'http_url', 'httpUrl') ||
    hasNonEmptyString(record, 'http_method', 'httpMethod') ||
    hasNonEmptyString(record, 'file_path', 'filePath') ||
    hasNonEmptyString(record, 'file_operation', 'fileOperation') ||
    hasNonEmptyString(record, 'db_statement', 'dbStatement') ||
    hasNonEmptyString(record, 'db_operation', 'dbOperation') ||
    hasNonEmptyString(record, 'db_system', 'dbSystem') ||
    typeof attributes['url.full'] === 'string' ||
    typeof attributes['http.url'] === 'string' ||
    typeof attributes['http.method'] === 'string' ||
    typeof attributes['file.path'] === 'string' ||
    typeof attributes['file.operation'] === 'string' ||
    typeof attributes['db.statement'] === 'string' ||
    typeof attributes['db.operation'] === 'string' ||
    typeof attributes['db.system'] === 'string' ||
    typeof attributes['shell.command'] === 'string' ||
    typeof attributes['mcp.method'] === 'string' ||
    typeof attributes['openbox.tool.name'] === 'string' ||
    typeof attributes['tool.name'] === 'string' ||
    typeof attributes.tool_name === 'string' ||
    typeof attributes['gen_ai.system'] === 'string'
  );
}

function withSpanHookContext<T>(
  span: T,
  event: {
    activity_id?: string;
    duration_ms?: number;
    end_time?: number;
    event_type?: string;
    start_time?: number;
  },
): T {
  if (!span || typeof span !== 'object' || Array.isArray(span)) {
    return span;
  }
  const record = span as Record<string, unknown>;
  const next: Record<string, unknown> = normalizeHookSpanAliases(record);
  if (
    event.activity_id &&
    (typeof next.activity_id !== 'string' || next.activity_id.trim() === '')
  ) {
    next.activity_id = event.activity_id;
  }
  if (!hasUsefulSpanDuration(next)) {
    const startTime = toSpanTimestampNs(event.start_time);
    const endTime = toSpanTimestampNs(event.end_time);
    const durationNs = durationMsToNs(event.duration_ms) ??
      (startTime !== undefined && endTime !== undefined
        ? Math.max(0, endTime - startTime)
        : undefined);
    if (startTime !== undefined) next.start_time = startTime;
    if (event.event_type === CANONICAL_EVENT_TYPE.ACTIVITY_STARTED) {
      next.end_time = null;
      next.duration_ns = null;
    } else if (event.event_type === CANONICAL_EVENT_TYPE.ACTIVITY_COMPLETED) {
      if (endTime !== undefined) next.end_time = endTime;
      if (durationNs !== undefined) next.duration_ns = durationNs;
    }
  }
  return next as T;
}

function normalizeHookSpanAliases(record: Record<string, unknown>): Record<string, unknown> {
  const attributes =
    record.attributes && typeof record.attributes === 'object'
      ? { ...(record.attributes as Record<string, unknown>) }
      : undefined;
  if (
    attributes &&
    typeof attributes['http.url'] !== 'string' &&
    typeof attributes['url.full'] === 'string'
  ) {
    attributes['http.url'] = attributes['url.full'];
  }
  const normalized: Record<string, unknown> = {
    ...record,
    ...(attributes ? { attributes } : {}),
    ...aliasField(record, 'span_id', 'spanId'),
    ...aliasField(record, 'trace_id', 'traceId'),
    ...aliasField(record, 'parent_span_id', 'parentSpanId'),
    ...aliasField(record, 'start_time', 'startTime'),
    ...aliasField(record, 'end_time', 'endTime'),
    ...aliasField(record, 'duration_ns', 'durationNs'),
    ...aliasField(record, 'semantic_type', 'semanticType'),
    ...aliasField(record, 'hook_type', 'hookType'),
    ...aliasField(record, 'request_body', 'requestBody'),
    ...aliasField(record, 'response_body', 'responseBody'),
    ...aliasField(record, 'request_headers', 'requestHeaders'),
    ...aliasField(record, 'response_headers', 'responseHeaders'),
  };
  if (Object.prototype.hasOwnProperty.call(normalized, 'events')) {
    normalized.events = normalizeHookSpanEvents(normalized.events);
  }
  if (Object.prototype.hasOwnProperty.call(normalized, 'status')) {
    const status = normalizeHookSpanStatus(normalized.status);
    if (status) {
      normalized.status = status;
    } else {
      delete normalized.status;
    }
  }
  normalizeHookSpanHeaderField(normalized, 'request_headers');
  normalizeHookSpanHeaderField(normalized, 'response_headers');
  return normalized;
}

function aliasField(
  record: Record<string, unknown>,
  snakeKey: string,
  camelKey: string,
): Record<string, unknown> {
  return record[snakeKey] === undefined && record[camelKey] !== undefined
    ? { [snakeKey]: record[camelKey] }
    : {};
}

function normalizeHookSpanEvents(events: unknown): Array<Record<string, unknown>> {
  if (!Array.isArray(events)) {
    return [];
  }
  return events.map((event) => {
    const record = toPlainRecord(event);
    return {
      attributes: toPlainRecord(record.attributes),
      name: typeof record.name === 'string' ? record.name : '',
      timestamp:
        typeof record.timestamp === 'number' && Number.isFinite(record.timestamp)
          ? record.timestamp
          : 0,
    };
  });
}

function normalizeHookSpanStatus(status: unknown): Record<string, unknown> | undefined {
  const record = toPlainRecord(status);
  const code = typeof record.code === 'string' ? record.code : undefined;
  const description =
    typeof record.description === 'string' || record.description === null
      ? record.description
      : undefined;
  if (!code && description === undefined) {
    return undefined;
  }
  return {
    ...(code ? { code } : {}),
    ...(description !== undefined ? { description } : {}),
  };
}

function normalizeHookSpanHeaderField(
  record: Record<string, unknown>,
  key: 'request_headers' | 'response_headers',
): void {
  if (!Object.prototype.hasOwnProperty.call(record, key)) {
    return;
  }
  const value = record[key];
  if (value === null) {
    return;
  }
  const headers = toStringRecord(value);
  if (headers) {
    record[key] = headers;
  } else {
    delete record[key];
  }
}

function toStringRecord(value: unknown): Record<string, string> | undefined {
  const record = toPlainRecord(value);
  const entries = Object.entries(record).flatMap(([key, entry]) =>
    typeof entry === 'string' ? ([[key, entry]] as const) : [],
  );
  if (entries.length === 0) {
    return undefined;
  }
  return Object.fromEntries(entries);
}

function toPlainRecord(value: unknown): Record<string, unknown> {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return {};
  }
  return value as Record<string, unknown>;
}

function hasNonEmptyString(
  record: Record<string, unknown>,
  ...keys: string[]
): boolean {
  return keys.some((key) => {
    const value = record[key];
    return typeof value === 'string' && value.trim() !== '';
  });
}

function hasUsefulSpanDuration(record: Record<string, unknown>): boolean {
  return (
    typeof record.duration_ns === 'number' &&
    Number.isFinite(record.duration_ns) &&
    record.duration_ns > 0
  );
}

function toSpanTimestampNs(value: unknown): number | undefined {
  if (typeof value !== 'number' || !Number.isFinite(value)) return undefined;
  return Math.trunc(value >= 1_000_000_000_000_000 ? value : value * 1_000_000);
}

function durationMsToNs(value: unknown): number | undefined {
  if (typeof value !== 'number' || !Number.isFinite(value)) return undefined;
  return Math.max(0, Math.trunc(value * 1_000_000));
}

function errorInfoFrom(value: unknown): { type: string; message: string } | undefined {
  if (value == null) return undefined;
  if (value instanceof Error) {
    return { type: value.name || 'Error', message: value.message };
  }
  return { type: typeof value, message: String(value) };
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Multiply a base interval by a uniform random factor in [1-fraction, 1+fraction].
 * Used by the approval poll loop to spread requests across a fleet.
 * Negative or > 1 jitter clamps to [0, 1] so callers can't create
 * negative or > 200% intervals by accident.
 */
function applyJitter(baseMs: number, fraction: number): number {
  const f = Math.max(0, Math.min(1, fraction));
  if (f === 0) return baseMs;
  const noise = (Math.random() * 2 - 1) * f; // [-f, f]
  return baseMs * (1 + noise);
}
`;
}

function emitNamespaceTypes(
  program: Program,
  project: Project,
  repoRoot: string,
  namespaceName: string,
  outRel: string,
): void {
  const ns = findNamespace(program, namespaceName);
  if (!ns) return;
  if (ns.enums.size === 0 && ns.models.size === 0) return;

  const out = project.createSourceFile(resolvePath(repoRoot, outRel), '', { overwrite: true });
  out.insertText(0, BANNER + '\n\n');

  for (const [enumName, enumType] of ns.enums) {
    const members = [...enumType.members.values()].map((m) =>
      JSON.stringify(m.value ?? m.name),
    );
    out.addStatements([`export type ${enumName} = ${members.join(' | ')};`, '']);
  }
  for (const [modelName, model] of ns.models) {
    // Skip the built-in Array/Record templates that show up under `models`
    // when other models reference them.
    if (modelName === 'Array' || modelName === 'Record') continue;
    out.addStatements([emitInterface(modelName, model), '']);
  }
}

function emitInterface(
  name: string,
  model: Model,
  options: { terminalVerdict?: boolean } = {},
): string {
  const lines: string[] = [`export interface ${name} {`];
  for (const [propName, prop] of model.properties) {
    const optional = prop.optional ? '?' : '';
    const propType =
      options.terminalVerdict && propName === 'ageResult'
        ? `GovernanceVerdictResponse['age_result']`
        : tspTypeToTs(prop.type);
    lines.push(`  ${quoteIdent(propName)}${optional}: ${propType};`);
  }
  lines.push('}');
  return lines.join('\n');
}

function emitInterfaceFromOps(name: string, iface: Interface): string {
  const lines: string[] = [`export interface ${name} {`];
  for (const [opName, op] of iface.operations) {
    lines.push(`  ${quoteIdent(opName)}${operationSignature(op)};`);
  }
  lines.push('}');
  return lines.join('\n');
}

function operationSignature(op: Operation): string {
  const params: string[] = [];
  for (const [pname, p] of op.parameters.properties) {
    const optional = p.optional ? '?' : '';
    params.push(`${quoteIdent(pname)}${optional}: ${tspTypeToTs(p.type)}`);
  }
  const ret = tspTypeToTs(op.returnType);
  return `(${params.join(', ')}): ${ret}`;
}

// Coarse Type → TS lowering. Sufficient for the env+cli surfaces; the
// govern protocol uses richer types (`unknown[]`, `utcDateTime`,
// `float64`) and will need this expanded when its emitter lands.
function tspTypeToTs(type: Type): string {
  switch (type.kind) {
    case 'Scalar': {
      const n = type.name;
      if (n === 'string' || n === 'url') return 'string';
      if (n === 'boolean') return 'boolean';
      if (n === 'numeric' || n === 'int8' || n === 'int16' || n === 'int32' || n === 'int64')
        return 'number';
      if (n === 'float' || n === 'float32' || n === 'float64' || n === 'decimal') return 'number';
      if (n === 'utcDateTime' || n === 'offsetDateTime' || n === 'plainDate') return 'string';
      if (n === 'unknown') return 'unknown';
      return 'string';
    }
    case 'Enum': {
      // Named enums round-trip as their TS type alias; only inline the
      // member union when the enum is anonymous.
      if (type.name) return type.name;
      const members = [...type.members.values()].map((m) =>
        JSON.stringify(m.value ?? m.name),
      );
      return members.join(' | ');
    }
    case 'Model': {
      // Built-in template instantiations: Array<T> -> T[], Record<T> -> Record<string, T>
      if (type.name === 'Array' && type.templateMapper?.args.length) {
        const arg = type.templateMapper.args[0] as Type;
        return `${tspTypeToTs(arg)}[]`;
      }
      if (type.name === 'Record' && type.templateMapper?.args.length) {
        const arg = type.templateMapper.args[0] as Type;
        return `Record<string, ${tspTypeToTs(arg)}>`;
      }
      if (type.name) return type.name;
      // Anonymous inline model.
      const props: string[] = [];
      for (const [pn, p] of type.properties) {
        const o = p.optional ? '?' : '';
        props.push(`${quoteIdent(pn)}${o}: ${tspTypeToTs(p.type)}`);
      }
      return `{ ${props.join('; ')} }`;
    }
    case 'Intrinsic':
      if (type.name === 'void') return 'void';
      if (type.name === 'null') return 'null';
      return 'unknown';
    case 'String':
      return JSON.stringify((type as { value: string }).value);
    case 'Number':
      return String((type as { value: number }).value);
    case 'Boolean':
      return String((type as { value: boolean }).value);
    case 'Union': {
      const variants = [...type.variants.values()].map((v) => tspTypeToTs(v.type));
      return variants.join(' | ');
    }
    case 'Tuple':
      return `[${(type as { values: Type[] }).values.map(tspTypeToTs).join(', ')}]`;
    default:
      return 'unknown';
  }
}

interface EnvVarBindingRow {
  field: string;
  envVar: { name: string; defaultValue: string | undefined };
}

function collectEnvVarBindings(program: Program, model: Model): EnvVarBindingRow[] {
  const out: EnvVarBindingRow[] = [];
  for (const [name, prop] of model.properties) {
    const ev = getEnvVar(program, prop);
    if (ev) out.push({ field: name, envVar: { name: ev.name, defaultValue: ev.defaultValue } });
  }
  return out;
}

function findNamespace(program: Program, name: string): Namespace | undefined {
  // Supports both simple ("OpenboxBackend") and dotted paths
  // ("OpenboxGovern.Adapters") for nested namespace lookup.
  if (name.includes('.')) {
    const parts = name.split('.');
    let cur: Namespace | undefined = program.getGlobalNamespaceType();
    for (const part of parts) {
      if (!cur) return undefined;
      cur = cur.namespaces.get(part);
    }
    return cur;
  }
  const stack = [program.getGlobalNamespaceType()];
  while (stack.length) {
    const ns = stack.pop()!;
    if (ns.name === name) return ns;
    for (const sub of ns.namespaces.values()) stack.push(sub);
  }
  return undefined;
}

function quoteIdent(name: string): string {
  return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(name) ? name : JSON.stringify(name);
}

function tsRegexLiteral(pattern: string): string {
  // RuntimeConfig stores patterns as JS regex source. Wrap in `/.../`
  // so the emitted file uses native RegExp literal form.
  return `/${pattern.replace(/\//g, '\\/')}/`;
}

/**
 * Compile an OpenAPI-style path template (`/agent/{id}/guardrails`) to
 * a regex literal that matches a realized path (`/agent/abc-123/guardrails`).
 * Each `{param}` becomes `[^/]+`. Other regex-special chars in the template
 * (rare; only `.` shows up in routes like `/governance.evaluate`) get
 * escaped. Anchored with `^…$` so a literal-prefix path can't false-match.
 */
function pathTemplateToRegex(template: string): string {
  // Escape regex-special chars EXCEPT the curly-brace placeholder syntax,
  // which we replace separately.
  const REGEX_SPECIALS = /[.*+?^${}()|[\]\\]/g;
  // First, separate placeholders from literal segments.
  const parts = template.split(/(\{[^}]+\})/);
  const compiled = parts
    .map((p) => {
      if (/^\{[^}]+\}$/.test(p)) return '[^/]+';
      return p.replace(REGEX_SPECIALS, '\\$&');
    })
    .join('');
  return `/^${compiled.replace(/\//g, '\\/')}$/`;
}
